/// Protocol type enum matching on-chain constants in AetherExecutor.sol.
///
/// `Default` resolves to [`ProtocolType::UniswapV2`] so structs that contain a
/// `ProtocolType` (e.g. ledger payloads) can keep deriving `Default`. UniswapV2
/// = 1 mirrors the on-chain enum's first variant and is the safest sentinel —
/// never silently maps to an undefined protocol code.
#[derive(Debug, Clone, Copy, Default, PartialEq, Eq, Hash, Serialize, Deserialize)]
#[repr(u8)]
pub enum ProtocolType {
    #[default]
    UniswapV2 = 1,
    UniswapV3 = 2,
    SushiSwap = 3,
    Curve = 4,
    BalancerV2 = 5,
    BancorV3 = 6,
    BalancerV3 = 7,
}

impl ProtocolType {
    /// Base gas cost for each protocol's swap
    pub fn base_gas(&self) -> u64 {
        match self {
            ProtocolType::UniswapV2 => 60_000,
            ProtocolType::UniswapV3 => 180_000,
            ProtocolType::SushiSwap => 60_000,
            ProtocolType::Curve => 130_000,
            ProtocolType::BalancerV2 => 120_000,
            ProtocolType::BancorV3 => 150_000,
            ProtocolType::BalancerV3 => 120_000,
        }
    }
}

/// Return the ERC20 decimals for a curated set of well-known mainnet tokens.
///
/// Address comparison is case-insensitive (compares raw 20-byte values, which
/// are checksum-agnostic). Returns `None` for any address not in the curated
/// set, in which case callers should fall back to an RPC `decimals()` call or
/// the ERC20 default of 18.
///
/// This is the static source of truth used to seed the price graph's per-vertex
/// decimals table before any RPC truth is available.
pub fn known_token_decimals(addr: &Address) -> Option<u8> {
    use addresses::{DAI, USDC, USDT, WBTC, WETH};
    match *addr {
        WETH => Some(18),
        USDC => Some(6),
        USDT => Some(6),
        DAI => Some(18),
        WBTC => Some(8),
        _ => None,
    }
}

/// Return the ERC20 `_balances` mapping storage slot for well-known mainnet
/// tokens. Used by revm profit extraction (`simulate_rpc_with_erc20_profit`).
/// Returns `None` for tokens without a known layout — callers fall back to
/// success-only simulation without balance-delta profit measurement.
pub fn erc20_balance_slot_for_token(addr: &Address) -> Option<U256> {
    use addresses::{DAI, USDC, USDT, WETH};
    match *addr {
        WETH => Some(U256::from(3u64)),
        USDC => Some(U256::from(9u64)),
        DAI | USDT => Some(U256::from(2u64)),
        _ => None,
    }
}

