//! Dynamic pool discovery service for Aether.
//!
//! Listens to factory `PoolCreated` / `PairCreated` events, validates pools
//! via analytical swap checks (and optional revm fork simulation), scores by
//! TVL and 24h volume, and maintains a ranked in-memory cache.

pub mod cache;
pub mod config;
pub mod events;
pub mod metrics;
pub mod scorer;
pub mod service;
pub mod types;
pub mod validator;
pub mod volume;

pub use cache::DiscoveryCache;
pub use config::{DiscoveryConfig, FactoryEntry, FactoryEventType};
pub use service::DiscoveryService;
pub use types::{DiscoveryEvent, PoolInfo, PoolScoreInputs, ValidationResult};

//! Prometheus metrics for the discovery service.

use std::sync::Arc;

use prometheus::{Counter, CounterVec, Histogram, HistogramOpts, Opts, Registry};

/// Discovery-specific Prometheus metrics.
#[derive(Clone)]
pub struct DiscoveryMetrics {
    pub events_received: Counter,
    pub pools_validated: Counter,
    pub pools_rejected: Counter,
    pub validation_latency_ms: Histogram,
    /// revm/analytical validation outcomes broken down by DEX and result, so
    /// operators can see per-protocol accept/reject rates (e.g. how many
    /// Uniswap V3 pools pass the full revm fork round-trip vs. how many
    /// Curve/Balancer/Bancor pools clear the analytical gate). Labels:
    /// `dex` ∈ {uniswap_v2, uniswap_v3, sushiswap, curve, balancer_v2,
    /// bancor_v3}, `result` ∈ {valid, low_liquidity, invalid}.
    pub revm_validations: CounterVec,
    pub volume_fetch_errors: Counter,
    pub volume_fetch_duration_ms: Histogram,
}

impl DiscoveryMetrics {
    pub fn register(registry: &Registry) -> Arc<Self> {
        let events_received = Counter::with_opts(Opts::new(
            "aether_discovery_events_received",
            "Factory PoolCreated/PairCreated events received",
        ))
        .expect("discovery_events_received");
        let pools_validated = Counter::with_opts(Opts::new(
            "aether_discovery_pools_validated",
            "Pools that passed validation and were admitted",
        ))
        .expect("discovery_pools_validated");
        let pools_rejected = Counter::with_opts(Opts::new(
            "aether_discovery_pools_rejected",
            "Pools rejected by validation",
        ))
        .expect("discovery_pools_rejected");
        let validation_latency_ms = Histogram::with_opts(
            HistogramOpts::new(
                "aether_discovery_validation_latency_ms",
                "Pool validation latency in milliseconds",
            )
            .buckets(vec![1.0, 5.0, 10.0, 25.0, 50.0, 100.0, 250.0, 500.0, 1000.0]),
        )
        .expect("discovery_validation_latency_ms");
        let revm_validations = CounterVec::new(
            Opts::new(
                "aether_discovery_revm_validations_total",
                "Pool validation outcomes by DEX and result (valid/low_liquidity/invalid)",
            ),
            &["dex", "result"],
        )
        .expect("discovery_revm_validations_total");
        let volume_fetch_errors = Counter::with_opts(Opts::new(
            "aether_discovery_volume_fetch_errors_total",
            "Volume provider fetch failures",
        ))
        .expect("discovery_volume_fetch_errors");
        let volume_fetch_duration_ms = Histogram::with_opts(
            HistogramOpts::new(
                "aether_discovery_volume_fetch_duration_ms",
                "Volume provider fetch duration in milliseconds",
            )
            .buckets(vec![1.0, 5.0, 10.0, 25.0, 50.0, 100.0, 250.0, 500.0]),
        )
        .expect("discovery_volume_fetch_duration_ms");

        registry
            .register(Box::new(events_received.clone()))
            .expect("register discovery_events_received");
        registry
            .register(Box::new(pools_validated.clone()))
            .expect("register discovery_pools_validated");
        registry
            .register(Box::new(pools_rejected.clone()))
            .expect("register discovery_pools_rejected");
        registry
            .register(Box::new(validation_latency_ms.clone()))
            .expect("register discovery_validation_latency_ms");
        registry
            .register(Box::new(revm_validations.clone()))
            .expect("register discovery_revm_validations_total");
        registry
            .register(Box::new(volume_fetch_errors.clone()))
            .expect("register discovery_volume_fetch_errors");
        registry
            .register(Box::new(volume_fetch_duration_ms.clone()))
            .expect("register discovery_volume_fetch_duration_ms");

        Arc::new(Self {
            events_received,
            pools_validated,
            pools_rejected,
            validation_latency_ms,
            revm_validations,
            volume_fetch_errors,
            volume_fetch_duration_ms,
        })
    }

    /// Record one validation outcome for a DEX. `dex` and `result` must be
    /// stable, low-cardinality label values (see [`DiscoveryMetrics`]).
    pub fn record_validation(&self, dex: &str, result: &str) {
        self.revm_validations.with_label_values(&[dex, result]).inc();
    }

    /// No-op metrics for unit tests.
    pub fn noop() -> Arc<Self> {
        let registry = Registry::new();
        Self::register(&registry)
    }
}

use crate::config::ScoringSettings;
use crate::types::PoolScoreInputs;

/// Compute the raw (unnormalised) pool score.
///
/// Formula: `sqrt(TVL) * volume_24h * (1 - fee) * (1 - slippage_estimate)`
pub fn raw_score(inputs: &PoolScoreInputs, settings: &ScoringSettings) -> f64 {
    let tvl = inputs.tvl_usd.max(0.0);
    let volume = inputs.volume_24h_usd.max(0.0);
    if tvl == 0.0 || volume == 0.0 {
        return 0.0;
    }

    let fee_factor = 1.0 - (inputs.fee_bps as f64 / 10_000.0);
    let slippage = inputs.slippage_estimate.clamp(0.0, 0.99);
    let slip_factor = 1.0 - slippage;

    (tvl.sqrt() * settings.tvl_weight)
        * (volume * settings.volume_weight)
        * fee_factor
        * slip_factor
}

/// Compute the normalised pool score in [0.0, 1.0] for discovery ranking.
///
/// Convenience wrapper over [`raw_score`] + [`normalise_score`].
pub fn compute_score(inputs: &PoolScoreInputs, settings: &ScoringSettings, max_raw: f64) -> f64 {
    normalise_score(raw_score(inputs, settings), max_raw)
}

/// Normalise a raw score into [0.0, 1.0] against the current cache maximum.
/// When `max_raw` is zero, returns 0.0.
pub fn normalise_score(raw: f64, max_raw: f64) -> f64 {
    if !raw.is_finite() || raw <= 0.0 {
        return 0.0;
    }
    if max_raw <= 0.0 || !max_raw.is_finite() {
        return 0.0;
    }
    (raw / max_raw).clamp(0.0, 1.0)
}

/// Default slippage estimate from config bps.
pub fn default_slippage_estimate(settings: &ScoringSettings) -> f64 {
    (settings.slippage_estimate_bps as f64 / 10_000.0).clamp(0.0, 0.99)
}

/// Estimate slippage for a Curve 2-coin stable pool (first-order proxy).
pub fn estimate_curve_slippage(
    balance_in: f64,
    balance_out: f64,
    amount_in_eth: f64,
    fee_bps: u32,
) -> f64 {
    if balance_in <= 0.0 || balance_out <= 0.0 || amount_in_eth <= 0.0 {
        return 1.0;
    }
    // Stable pools have lower slippage than CP-AMM at equal depth; scale down V2 estimate.
    estimate_v2_slippage(balance_in, balance_out, amount_in_eth, fee_bps) * 0.35
}

/// Estimate slippage for a Balancer weighted pool (50/50 default).
pub fn estimate_balancer_v3_slippage(
    balance_in: f64,
    balance_out: f64,
    amount_in_eth: f64,
    fee_bps: u32,
) -> f64 {
    if balance_in <= 0.0 || balance_out <= 0.0 || amount_in_eth <= 0.0 {
        return 1.0;
    }
    estimate_v2_slippage(balance_in, balance_out, amount_in_eth, fee_bps) * 0.85
}

/// Protocol-aware slippage estimate for discovery scoring.
pub fn estimate_protocol_slippage(
    protocol: aether_common::types::ProtocolType,
    balance_in: f64,
    balance_out: f64,
    amount_in_eth: f64,
    fee_bps: u32,
) -> f64 {
    match protocol {
        aether_common::types::ProtocolType::Curve => {
            estimate_curve_slippage(balance_in, balance_out, amount_in_eth, fee_bps)
        }
        aether_common::types::ProtocolType::BalancerV3 => {
            estimate_balancer_v3_slippage(balance_in, balance_out, amount_in_eth, fee_bps)
        }
        _ => estimate_v2_slippage(balance_in, balance_out, amount_in_eth, fee_bps),
    }
}

/// Estimate slippage for a constant-product pool given reserves and swap size.
pub fn estimate_v2_slippage(
    reserve_in: f64,
    reserve_out: f64,
    amount_in_eth: f64,
    fee_bps: u32,
) -> f64 {
    if reserve_in <= 0.0 || reserve_out <= 0.0 || amount_in_eth <= 0.0 {
        return 1.0;
    }
    let fee_factor = 1.0 - (fee_bps as f64 / 10_000.0);
    let amount_in = amount_in_eth * fee_factor;
    let spot = reserve_out / reserve_in;
    let amount_out = (amount_in * reserve_out) / (reserve_in + amount_in);
    let effective_rate = amount_out / amount_in;
    if spot <= 0.0 {
        return 1.0;
    }
    ((spot - effective_rate) / spot).clamp(0.0, 0.99)
}

#[cfg(test)]
mod tests {
    use super::*;

    fn settings() -> ScoringSettings {
        ScoringSettings::default()
    }

    #[test]
    fn formula_basic() {
        let inputs = PoolScoreInputs {
            tvl_usd: 1_000_000.0,
            volume_24h_usd: 500_000.0,
            fee_bps: 30,
            slippage_estimate: 0.005,
        };
        let raw = raw_score(&inputs, &settings());
        assert!(raw > 0.0);
        // sqrt(1e6) * 5e5 * 0.997 * 0.995
        let expected = 1000.0 * 500_000.0 * 0.997 * 0.995;
        assert!((raw - expected).abs() < 1.0);
    }

    #[test]
    fn zero_tvl_returns_zero() {
        let inputs = PoolScoreInputs {
            tvl_usd: 0.0,
            volume_24h_usd: 100_000.0,
            fee_bps: 30,
            slippage_estimate: 0.01,
        };
        assert_eq!(raw_score(&inputs, &settings()), 0.0);
    }

    #[test]
    fn zero_volume_returns_zero() {
        let inputs = PoolScoreInputs {
            tvl_usd: 100_000.0,
            volume_24h_usd: 0.0,
            fee_bps: 30,
            slippage_estimate: 0.01,
        };
        assert_eq!(raw_score(&inputs, &settings()), 0.0);
    }

    #[test]
    fn normalise_at_max_is_one() {
        let raw = 1_000_000.0;
        assert_eq!(normalise_score(raw, raw), 1.0);
    }

    #[test]
    fn normalise_half() {
        assert!((normalise_score(50.0, 100.0) - 0.5).abs() < 1e-9);
    }

    #[test]
    fn normalise_zero_raw() {
        assert_eq!(normalise_score(0.0, 100.0), 0.0);
    }

    #[test]
    fn normalise_zero_max() {
        assert_eq!(normalise_score(10.0, 0.0), 0.0);
    }

    #[test]
    fn normalise_negative_clamped() {
        assert_eq!(normalise_score(-5.0, 100.0), 0.0);
    }

    #[test]
    fn normalise_above_max_clamped() {
        assert_eq!(normalise_score(200.0, 100.0), 1.0);
    }

    #[test]
    fn compute_score_matches_raw_and_normalise() {
        let inputs = PoolScoreInputs {
            tvl_usd: 1_000_000.0,
            volume_24h_usd: 500_000.0,
            fee_bps: 30,
            slippage_estimate: 0.005,
        };
        let raw = raw_score(&inputs, &settings());
        let via_wrapper = compute_score(&inputs, &settings(), raw);
        assert!((via_wrapper - 1.0).abs() < 1e-9);
    }

    #[test]
    fn compute_score_zero_when_max_zero() {
        let inputs = PoolScoreInputs {
            tvl_usd: 100.0,
            volume_24h_usd: 100.0,
            fee_bps: 30,
            slippage_estimate: 0.01,
        };
        assert_eq!(compute_score(&inputs, &settings(), 0.0), 0.0);
    }

    #[test]
    fn higher_fee_lowers_score() {
        let base = PoolScoreInputs {
            tvl_usd: 1_000_000.0,
            volume_24h_usd: 100_000.0,
            fee_bps: 30,
            slippage_estimate: 0.01,
        };
        let high_fee = PoolScoreInputs {
            fee_bps: 100,
            ..base
        };
        assert!(raw_score(&base, &settings()) > raw_score(&high_fee, &settings()));
    }

    #[test]
    fn higher_slippage_lowers_score() {
        let low_slip = PoolScoreInputs {
            tvl_usd: 500_000.0,
            volume_24h_usd: 50_000.0,
            fee_bps: 30,
            slippage_estimate: 0.001,
        };
        let high_slip = PoolScoreInputs {
            slippage_estimate: 0.1,
            ..low_slip
        };
        assert!(raw_score(&low_slip, &settings()) > raw_score(&high_slip, &settings()));
    }

    #[test]
    fn v2_slippage_increases_with_trade_size() {
        let small = estimate_v2_slippage(1000.0, 1000.0, 0.001, 30);
        let large = estimate_v2_slippage(1000.0, 1000.0, 1.0, 30);
        assert!(large > small);
    }

    #[test]
    fn default_slippage_from_bps() {
        assert!((default_slippage_estimate(&settings()) - 0.005).abs() < 1e-9);
    }

    #[test]
    fn curve_slippage_below_v2_at_equal_depth() {
        let curve = estimate_curve_slippage(1e6, 1e6, 0.5, 4);
        let v2 = estimate_v2_slippage(1e6, 1e6, 0.5, 4);
        assert!(curve < v2);
    }

    #[test]
    fn balancer_v3_slippage_positive() {
        assert!(estimate_balancer_v3_slippage(1e6, 1e6, 0.1, 10) > 0.0);
    }

    #[test]
    fn protocol_slippage_routes_curve_and_balancer_v3() {
        use aether_common::types::ProtocolType;
        assert!(estimate_protocol_slippage(ProtocolType::Curve, 1e6, 1e6, 0.1, 4) > 0.0);
        assert!(estimate_protocol_slippage(ProtocolType::BalancerV3, 1e6, 1e6, 0.1, 10) > 0.0);
    }
}

//! Discovery service orchestrating validation, scoring, and cache management.

use std::sync::Arc;

use aether_common::types::ProtocolType;
use alloy::network::Ethereum;
use alloy::primitives::{Address, U256};
use alloy::providers::{DynProvider, Provider, ProviderBuilder};
use alloy::sol_types::SolCall;
use tokio::sync::broadcast;
use tracing::{debug, info};

use crate::cache::{DiscoveryCache, SharedDiscoveryCache};
use crate::config::DiscoveryConfig;
use crate::events::FactoryPoolCreated;
use crate::scorer::{default_slippage_estimate, estimate_protocol_slippage};
use crate::types::{PoolInfo, PoolScoreInputs, ValidationResult};
use crate::metrics::DiscoveryMetrics;
use crate::validator::{validate_pool_revm, validate_v2_reserves};
use crate::volume::VolumeProvider;

/// TVL / volume data source for scoring enrichment.
pub trait PoolMetricsSource: Send + Sync {
    fn fetch_metrics(
        &self,
        pool: Address,
        token0: Address,
        token1: Address,
        protocol: ProtocolType,
    ) -> PoolScoreInputs;
}

/// On-chain reserve-based metrics (multicall / RPC fallback).
pub struct OnChainMetricsSource {
    provider: Option<DynProvider<Ethereum>>,
    slippage_bps: u32,
    swap_eth: f64,
}

impl OnChainMetricsSource {
    pub fn new(provider: Option<DynProvider<Ethereum>>, config: &DiscoveryConfig) -> Self {
        Self {
            provider,
            slippage_bps: config.scoring.slippage_estimate_bps,
            swap_eth: config.discovery.validation_swap_eth,
        }
    }
}

impl PoolMetricsSource for OnChainMetricsSource {
    fn fetch_metrics(
        &self,
        pool: Address,
        token0: Address,
        token1: Address,
        protocol: ProtocolType,
    ) -> PoolScoreInputs {
        let default_slip = (self.slippage_bps as f64 / 10_000.0).clamp(0.0, 0.99);

        let Some(provider) = &self.provider else {
            return PoolScoreInputs {
                tvl_usd: 100_000.0,
                volume_24h_usd: 10_000.0,
                fee_bps: 30,
                slippage_estimate: default_slip,
            };
        };

        // Blocking fetch in sync trait — callers run on blocking thread or use defaults.
        let rt = tokio::runtime::Handle::current();
        let reserves = match protocol {
            ProtocolType::Curve => rt.block_on(fetch_curve_balances(provider, pool)),
            ProtocolType::BalancerV3 => {
                rt.block_on(fetch_balancer_v3_balances(provider, pool, token0, token1))
            }
            _ => rt
                .block_on(fetch_v2_reserves(provider, pool))
                .map(|(r0, r1, fee)| (r0, r1, fee)),
        };

        match reserves {
            Some((r0, r1, fee_bps)) => {
                let r0_f = u256_to_f64(r0);
                let r1_f = u256_to_f64(r1);
                let tvl_usd = estimate_tvl_usd(token0, token1, r0_f, r1_f);
                let (bal_in, bal_out) = if token0 == aether_common::types::addresses::WETH {
                    (r0_f, r1_f)
                } else if token1 == aether_common::types::addresses::WETH {
                    (r1_f, r0_f)
                } else {
                    (r0_f, r1_f)
                };
                let slip = estimate_protocol_slippage(
                    protocol,
                    bal_in,
                    bal_out,
                    self.swap_eth,
                    fee_bps,
                );
                PoolScoreInputs {
                    tvl_usd,
                    volume_24h_usd: {
                        let vol_src = crate::volume::VolumeSource::from_config(
                            "proxy",
                            String::new(),
                            None,
                        );
                        vol_src.volume_24h_usd(pool, token0, token1, protocol, tvl_usd)
                    },
                    fee_bps,
                    slippage_estimate: slip.max(default_slip),
                }
            }
            None => PoolScoreInputs {
                tvl_usd: 0.0,
                volume_24h_usd: 0.0,
                fee_bps: 30,
                slippage_estimate: default_slip,
            },
        }
    }
}

async fn fetch_curve_balances(
    provider: &DynProvider<Ethereum>,
    pool: Address,
) -> Option<(U256, U256, u32)> {
    alloy::sol! {
        function balances(uint256 i) external view returns (uint256);
    }
    let mut out_bal = [U256::ZERO; 2];
    for (idx, slot) in out_bal.iter_mut().enumerate() {
        let out = provider
            .call(
                alloy::rpc::types::TransactionRequest::default()
                    .to(pool)
                    .input(balancesCall { i: U256::from(idx as u64) }.abi_encode().into()),
            )
            .await
            .ok()?;
        if out.len() < 32 {
            return None;
        }
        *slot = U256::from_be_slice(&out[0..32]);
    }
    Some((out_bal[0], out_bal[1], 4))
}

async fn fetch_balancer_v3_balances(
    provider: &DynProvider<Ethereum>,
    pool: Address,
    token0: Address,
    token1: Address,
) -> Option<(U256, U256, u32)> {
    alloy::sol! {
        function balanceOf(address account) external view returns (uint256);
    }
    let b0 = provider
        .call(
            alloy::rpc::types::TransactionRequest::default()
                .to(token0)
                .input(balanceOfCall { account: pool }.abi_encode().into()),
        )
        .await
        .ok()?;
    let b1 = provider
        .call(
            alloy::rpc::types::TransactionRequest::default()
                .to(token1)
                .input(balanceOfCall { account: pool }.abi_encode().into()),
        )
        .await
        .ok()?;
    if b0.len() < 32 || b1.len() < 32 {
        return None;
    }
    Some((
        U256::from_be_slice(&b0[b0.len() - 32..]),
        U256::from_be_slice(&b1[b1.len() - 32..]),
        10,
    ))
}

async fn fetch_v2_reserves(
    provider: &DynProvider<Ethereum>,
    pool: Address,
) -> Option<(U256, U256, u32)> {
    alloy::sol! {
        function getReserves() external view returns (uint112 reserve0, uint112 reserve1, uint32 blockTimestampLast);
    }
    let out = provider
        .call(
            alloy::rpc::types::TransactionRequest::default()
                .to(pool)
                .input(getReservesCall {}.abi_encode().into()),
        )
        .await
        .ok()?;
    if out.len() < 64 {
        return None;
    }
    let r0 = U256::from_be_slice(&out[0..32]);
    let r1 = U256::from_be_slice(&out[32..64]);
    Some((r0, r1, 30))
}

fn u256_to_f64(v: U256) -> f64 {
    v.to_string().parse::<f64>().unwrap_or(0.0) / 1e18
}

fn estimate_tvl_usd(token0: Address, token1: Address, r0: f64, r1: f64) -> f64 {
    use aether_common::types::addresses::{USDC, WETH};
    const ETH_USD: f64 = 3000.0;
    if token0 == WETH {
        return r0 * ETH_USD * 2.0;
    }
    if token1 == WETH {
        return r1 * ETH_USD * 2.0;
    }
    if token0 == USDC || token1 == USDC {
        return (r0 + r1) * 2.0;
    }
    (r0 + r1).max(1.0)
}

/// Validation used when no RPC provider is configured (unit tests, offline
/// scoring mode). Without a fork we cannot run revm, so V2/Sushi pools are
/// checked against assumed-healthy reserves and the remaining protocols are
/// accepted subject to a sane fee bound. The live path
/// (`validator::validate_pool_revm`) supersedes this whenever a provider
/// exists.
fn offline_validate(event: &FactoryPoolCreated, swap_eth: f64) -> ValidationResult {
    match event.protocol {
        ProtocolType::UniswapV2 | ProtocolType::SushiSwap => validate_v2_reserves(
            event.token0,
            event.token1,
            event.protocol,
            event.fee_bps,
            U256::from(1_000_000_000_000_000_000u64),
            U256::from(1_000_000_000_000_000_000u64),
            swap_eth,
        ),
        ProtocolType::Curve | ProtocolType::BalancerV3 => validate_v2_reserves(
            event.token0,
            event.token1,
            ProtocolType::UniswapV2,
            event.fee_bps,
            U256::from(1_000_000_000_000_000_000u64),
            U256::from(1_000_000_000_000_000_000u64),
            swap_eth,
        ),
        _ => {
            if event.fee_bps <= 10_000 {
                ValidationResult::Valid
            } else {
                ValidationResult::Invalid("invalid fee".into())
            }
        }
    }
}

/// Main discovery service API.
pub struct DiscoveryService {
    config: DiscoveryConfig,
    cache: SharedDiscoveryCache,
    metrics_source: Arc<dyn PoolMetricsSource>,
    provider: Option<DynProvider<Ethereum>>,
    event_tx: broadcast::Sender<crate::types::DiscoveryEvent>,
    metrics: Option<Arc<DiscoveryMetrics>>,
}

/// Connect an erased alloy provider from an HTTP/WS RPC URL.
pub async fn connect_rpc_provider(rpc_url: &str) -> Option<DynProvider<Ethereum>> {
    ProviderBuilder::new()
        .connect(rpc_url)
        .await
        .ok()
        .map(|p| p.erased())
}

impl DiscoveryService {
    pub fn new(config: DiscoveryConfig) -> Self {
        Self::with_provider(config, None)
    }

    pub async fn with_rpc_url(config: DiscoveryConfig, rpc_url: &str) -> Self {
        let provider = connect_rpc_provider(rpc_url).await;
        Self::with_provider(config, provider)
    }

    pub fn with_provider(config: DiscoveryConfig, provider: Option<DynProvider<Ethereum>>) -> Self {
        let (event_tx, _) = broadcast::channel(1024);
        let cache = Arc::new(DiscoveryCache::new(
            &config.discovery,
            config.scoring.clone(),
            event_tx.clone(),
        ));
        let metrics_source: Arc<dyn PoolMetricsSource> = Arc::new(OnChainMetricsSource::new(
            provider.clone(),
            &config,
        ));
        Self {
            config,
            cache,
            metrics_source,
            provider,
            event_tx,
            metrics: None,
        }
    }

    /// Attach Prometheus metrics for discovery validation and events.
    pub fn set_metrics(&mut self, metrics: Arc<DiscoveryMetrics>) {
        self.metrics = Some(metrics);
    }

    pub fn metrics(&self) -> Option<Arc<DiscoveryMetrics>> {
        self.metrics.clone()
    }

    pub fn config(&self) -> &DiscoveryConfig {
        &self.config
    }

    pub fn cache(&self) -> &SharedDiscoveryCache {
        &self.cache
    }

    /// Return top-N pools sorted by normalised score.
    pub fn get_top_n(&self, n: usize) -> Vec<PoolInfo> {
        self.cache.get_top_n(n)
    }

    /// Subscribe to discovery events (pool added/updated/pruned).
    pub fn subscribe_events(&self) -> broadcast::Receiver<crate::types::DiscoveryEvent> {
        self.event_tx.subscribe()
    }

    /// Ingest a factory `PoolCreated` event. Returns `true` if the pool was admitted.
    pub async fn ingest_pool_created(&self, event: FactoryPoolCreated) -> bool {
        if !self.config.discovery.enabled {
            return false;
        }

        if self.cache.contains(&event.pool) {
            debug!(pool = %event.pool, "pool already in cache");
            return false;
        }

        let validation = self.validate_pool(&event).await;
        match validation {
            ValidationResult::Valid => {}
            ValidationResult::LowLiquidity => {
                debug!(pool = %event.pool, "pool rejected: low liquidity");
                return false;
            }
            ValidationResult::Invalid(reason) => {
                debug!(pool = %event.pool, reason, "pool rejected: invalid");
                return false;
            }
        }

        let mut inputs = self.metrics_source.fetch_metrics(
            event.pool,
            event.token0,
            event.token1,
            event.protocol,
        );
        inputs.fee_bps = event.fee_bps;
        if inputs.slippage_estimate == 0.0 {
            inputs.slippage_estimate = default_slippage_estimate(&self.config.scoring);
        }

        let info = PoolInfo {
            address: event.pool,
            token0: event.token0,
            token1: event.token1,
            protocol: event.protocol,
            fee_bps: event.fee_bps,
            score: 0.0,
            tvl_usd: inputs.tvl_usd,
            volume_24h_usd: inputs.volume_24h_usd,
            slippage_estimate: inputs.slippage_estimate,
            discovered_at: 0,
        };

        self.cache.upsert(info, inputs);
        info!(pool = %event.pool, ?event.protocol, "pool admitted to discovery cache");
        true
    }

    /// Manually insert a pre-validated pool (for tests and static seeding).
    pub fn insert_validated(&self, info: PoolInfo, inputs: PoolScoreInputs) -> PoolInfo {
        self.cache.upsert(info, inputs)
    }

    async fn validate_pool(&self, event: &FactoryPoolCreated) -> ValidationResult {
        let swap_eth = self.config.discovery.validation_swap_eth;
        let validation_mode = self.config.discovery.validation_mode.clone();

        // Offline path (unit tests / no RPC configured): no fork available, so
        // fall back to analytical acceptance. With a provider, every protocol
        // goes through the unified revm/analytical validator.
        let Some(provider) = &self.provider else {
            return offline_validate(event, swap_eth);
        };

        let pool = PoolInfo {
            address: event.pool,
            token0: event.token0,
            token1: event.token1,
            protocol: event.protocol,
            fee_bps: event.fee_bps,
            score: 0.0,
            tvl_usd: 0.0,
            volume_24h_usd: 0.0,
            slippage_estimate: 0.0,
            discovered_at: 0,
        };
        validate_pool_revm(provider, &pool, swap_eth, &validation_mode, self.metrics.clone()).await
    }

    /// Prune stale / low-score pools. Returns number removed.
    pub fn prune(&self, min_score: f64) -> usize {
        self.cache.prune(min_score)
    }

    /// Spawn background prune loop.
    pub fn spawn_prune_task(self: Arc<Self>, mut shutdown: tokio::sync::watch::Receiver<bool>) {
        let interval_secs = self.config.discovery.prune_interval_secs;
        tokio::spawn(async move {
            let mut ticker =
                tokio::time::interval(std::time::Duration::from_secs(interval_secs));
            loop {
                tokio::select! {
                    _ = ticker.tick() => {
                        let removed = self.prune(0.01);
                        if removed > 0 {
                            info!(removed, "discovery cache pruned");
                        }
                    }
                    _ = shutdown.changed() => {
                        if *shutdown.borrow() { break; }
                    }
                }
            }
        });
    }
}

#[cfg(test)]
mod tests {
    use super::*;
    use alloy::primitives::address;

    fn test_config() -> DiscoveryConfig {
        DiscoveryConfig {
            discovery: crate::config::DiscoverySettings {
                enabled: true,
                max_pools: 1000,
                ..Default::default()
            },
            ..Default::default()
