        .nonce(1)
        .chain_id(Some(chain_id))
        .build_fill();
    if !revm_transact_success(&mut evm, approve_tx) {
        return ValidationResult::Invalid("revm WETH vault approve reverted".into());
    }

    let buy_data = IBalancerVaultSwap::swapCall {
