        let (post_in, post_out) = predict_v2_post_state(1000.0, 1000.0, 100.0, 0.997);
        let k_before = 1000.0 * 1000.0;
        let k_after = post_in * post_out;
        assert!(k_after > k_before, "fee should increase k");
    }

