    /// In-memory sink used by the pipeline test to assert that a row was
    /// produced without standing up Postgres.
    pub(crate) struct CapturingSink {
        pub seen: Mutex<Vec<NewMempoolPrediction>>,
    }

    impl CapturingSink {
        pub fn new() -> Self {
            Self {
                seen: Mutex::new(Vec::new()),
            }
        }
