    fn test_resolver(key: &str) -> Option<String> {
        match key {
            "AETHER_TEST_KEY_XYZ" => Some("hello".to_string()),
            "AETHER_A" => Some("1".to_string()),
            "AETHER_B" => Some("2".to_string()),
            "AETHER_URL" => Some("wss://alchemy.example.com/v2/key".to_string()),
            _ => None,
        }
    }

