use crate::event_decoder::PoolEvent;
use std::sync::Arc;
use tokio::sync::broadcast;
use tracing::warn;

/// Channel capacity for event dispatch
const CHANNEL_CAPACITY: usize = 10_000;

/// Event channels for broadcasting decoded events to consumers
pub struct EventChannels {
    pub pool_updates_tx: broadcast::Sender<PoolEvent>,
    pub new_block_tx: broadcast::Sender<NewBlockEvent>,
    pub pending_tx_tx: broadcast::Sender<PendingTxEvent>,
}

/// New block notification
///
/// `tx_hashes` is populated by the polling provider so downstream
/// observers (e.g. the mempool first-seen tracker) can compute per-tx
/// inclusion latency without issuing a separate `eth_getBlockByNumber`
/// RPC. Empty `Arc<Vec<_>>` is the safe default when the hash list isn't
/// available (e.g. some WS subscriptions, the unit-test stubs).
#[derive(Debug, Clone, Default)]
pub struct NewBlockEvent {
    pub block_number: u64,
    pub timestamp: u64,
    pub base_fee: u128,
    pub gas_limit: u64,
    pub tx_hashes: Arc<Vec<alloy::primitives::B256>>,
}

/// Pending transaction notification
///
/// `first_seen_unix_nanos` is stamped at the moment the ingestion source
/// (Alchemy WS, MEV-Share SSE, …) hands the tx to the broadcast layer.
/// `0` means "not stamped" — downstream observers skip latency reporting
/// for those events rather than emitting bogus 1970-epoch deltas. This
/// keeps the field optional in spirit without paying for `Option`'s
/// branch on the hot path.
#[derive(Debug, Clone, Default)]
pub struct PendingTxEvent {
    pub tx_hash: alloy::primitives::B256,
    pub from: alloy::primitives::Address,
    pub to: Option<alloy::primitives::Address>,
    pub value: alloy::primitives::U256,
    pub input: Vec<u8>,
    pub gas_price: u128,
    pub first_seen_unix_nanos: u64,
    /// Canonical EIP-2718 signed bytes of the pending tx, captured at the
    /// subscription boundary. Used by the mempool-backrun path to place the
    /// victim as `txs[0]` in the Flashbots bundle. Empty only when the source
    /// could not produce verified raw bytes (such events are dropped before
    /// dispatch on the backrun path).
    pub raw_tx: Vec<u8>,
}

impl EventChannels {
    pub fn new() -> Self {
        let (pool_updates_tx, _) = broadcast::channel(CHANNEL_CAPACITY);
        let (new_block_tx, _) = broadcast::channel(CHANNEL_CAPACITY);
        let (pending_tx_tx, _) = broadcast::channel(CHANNEL_CAPACITY);

        Self {
            pool_updates_tx,
            new_block_tx,
            pending_tx_tx,
        }
    }

    /// Subscribe to pool update events
    pub fn subscribe_pool_updates(&self) -> broadcast::Receiver<PoolEvent> {
        self.pool_updates_tx.subscribe()
    }

    /// Subscribe to new block events
    pub fn subscribe_new_blocks(&self) -> broadcast::Receiver<NewBlockEvent> {
        self.new_block_tx.subscribe()
    }

    /// Subscribe to pending transaction events
    pub fn subscribe_pending_txs(&self) -> broadcast::Receiver<PendingTxEvent> {
        self.pending_tx_tx.subscribe()
    }

    /// Dispatch a pool update event
    #[tracing::instrument(level = "debug", skip_all, name = "ingest.pool_update")]
    pub fn dispatch_pool_update(&self, event: PoolEvent) {
        match self.pool_updates_tx.send(event) {
            Ok(_n) => {}
            Err(_) => warn!("No pool update subscribers"),
        }
    }

    /// Dispatch a new block event
    #[tracing::instrument(level = "debug", skip_all, name = "ingest.new_block", fields(block_number = event.block_number))]
    pub fn dispatch_new_block(&self, event: NewBlockEvent) {
        match self.new_block_tx.send(event) {
            Ok(_) => {}
            Err(_) => warn!("No new block subscribers"),
        }
    }

    /// Dispatch a pending tx event
    #[tracing::instrument(level = "debug", skip_all, name = "ingest.pending_tx")]
    pub fn dispatch_pending_tx(&self, event: PendingTxEvent) {
        match self.pending_tx_tx.send(event) {
            Ok(_) => {}
            Err(_) => warn!("No pending tx subscribers"),
        }
    }

    /// Get current subscriber counts
    pub fn subscriber_counts(&self) -> (usize, usize, usize) {
        (
            self.pool_updates_tx.receiver_count(),
            self.new_block_tx.receiver_count(),
            self.pending_tx_tx.receiver_count(),
        )
    }
}

impl Default for EventChannels {
    fn default() -> Self {
        Self::new()
    }
}

#[cfg(test)]
mod tests {
    use super::*;
    use alloy::primitives::{Address, B256, U256};

    // ── Channel creation tests ──

    #[test]
    fn test_event_channels_new() {
        let channels = EventChannels::new();
        let (pool, block, tx) = channels.subscriber_counts();
        assert_eq!(pool, 0);
        assert_eq!(block, 0);
        assert_eq!(tx, 0);
    }

    #[test]
    fn test_event_channels_default() {
        let channels = EventChannels::default();
        let (pool, block, tx) = channels.subscriber_counts();
        assert_eq!(pool, 0);
        assert_eq!(block, 0);
        assert_eq!(tx, 0);
    }

    // ── Subscribe/dispatch pool updates ──

    #[tokio::test]
    async fn test_subscribe_and_dispatch_pool_update() {
        let channels = EventChannels::new();
        let mut rx = channels.subscribe_pool_updates();

        let event = PoolEvent::ReserveUpdate {
            pool: Address::ZERO,
            protocol: aether_common::types::ProtocolType::UniswapV2,
            reserve0: U256::from(1000u64),
            reserve1: U256::from(2000u64),
        };

        channels.dispatch_pool_update(event);

        let received = rx.recv().await.expect("should receive pool update");
        let PoolEvent::ReserveUpdate {
            reserve0, reserve1, ..
        } = received
        else {
            panic!("dispatch returned unexpected variant: {received:?}");
        };
        assert_eq!(reserve0, U256::from(1000u64));
        assert_eq!(reserve1, U256::from(2000u64));
    }

    // ── Subscribe/dispatch new block ──

    #[tokio::test]
    async fn test_subscribe_and_dispatch_new_block() {
        let channels = EventChannels::new();
        let mut rx = channels.subscribe_new_blocks();

        let event = NewBlockEvent {
            block_number: 18_000_000,
            timestamp: 1_700_000_000,
            base_fee: 30_000_000_000, // 30 gwei
            gas_limit: 30_000_000,
            ..Default::default()
        };

        channels.dispatch_new_block(event);

        let received = rx.recv().await.expect("should receive new block");
        assert_eq!(received.block_number, 18_000_000);
        assert_eq!(received.timestamp, 1_700_000_000);
        assert_eq!(received.base_fee, 30_000_000_000);
        assert_eq!(received.gas_limit, 30_000_000);
    }

    // ── Subscribe/dispatch pending tx ──

    #[tokio::test]
    async fn test_subscribe_and_dispatch_pending_tx() {
        let channels = EventChannels::new();
        let mut rx = channels.subscribe_pending_txs();

        let event = PendingTxEvent {
            tx_hash: B256::ZERO,
            from: Address::ZERO,
            to: Some(Address::ZERO),
            value: U256::from(1_000_000_000_000_000_000u64),
            input: vec![0xaa, 0xbb],
            gas_price: 50_000_000_000,
            raw_tx: vec![0x02, 0xcc],
            ..Default::default()
        };

        channels.dispatch_pending_tx(event);

        let received = rx.recv().await.expect("should receive pending tx");
        assert_eq!(received.value, U256::from(1_000_000_000_000_000_000u64));
        assert_eq!(received.input, vec![0xaa, 0xbb]);
        assert_eq!(received.gas_price, 50_000_000_000);
    }

    // ── Multiple subscribers ──

    #[tokio::test]
    async fn test_multiple_pool_update_subscribers() {
        let channels = EventChannels::new();
        let mut rx1 = channels.subscribe_pool_updates();
        let mut rx2 = channels.subscribe_pool_updates();
        let mut rx3 = channels.subscribe_pool_updates();

        assert_eq!(channels.subscriber_counts().0, 3);

        let event = PoolEvent::V3Update {
            pool: Address::ZERO,
            sqrt_price_x96: U256::from(999u64),
            liquidity: 12345,
            tick: -50,
        };

        channels.dispatch_pool_update(event);

        // All three should receive the event
        let r1 = rx1.recv().await.expect("rx1 should receive");
        let r2 = rx2.recv().await.expect("rx2 should receive");
        let r3 = rx3.recv().await.expect("rx3 should receive");

        for received in [r1, r2, r3] {
            let PoolEvent::V3Update { tick, liquidity, .. } = received else {
                panic!("dispatch returned unexpected variant: {received:?}");
            };
            assert_eq!(tick, -50);
            assert_eq!(liquidity, 12345);
        }
    }

    #[tokio::test]
    async fn test_multiple_block_subscribers() {
        let channels = EventChannels::new();
        let mut rx1 = channels.subscribe_new_blocks();
        let mut rx2 = channels.subscribe_new_blocks();

        assert_eq!(channels.subscriber_counts().1, 2);

        channels.dispatch_new_block(NewBlockEvent {
            block_number: 42,
            timestamp: 100,
            base_fee: 10,
            gas_limit: 30_000_000,
            ..Default::default()
        });

        let r1 = rx1.recv().await.unwrap();
        let r2 = rx2.recv().await.unwrap();
        assert_eq!(r1.block_number, 42);
        assert_eq!(r2.block_number, 42);
    }

    // ── Subscriber count tracking ──

    #[test]
    fn test_subscriber_count_tracks_subscriptions() {
        let channels = EventChannels::new();

        assert_eq!(channels.subscriber_counts(), (0, 0, 0));

        let _rx1 = channels.subscribe_pool_updates();
        assert_eq!(channels.subscriber_counts(), (1, 0, 0));

        let _rx2 = channels.subscribe_new_blocks();
        assert_eq!(channels.subscriber_counts(), (1, 1, 0));

        let _rx3 = channels.subscribe_pending_txs();
        assert_eq!(channels.subscriber_counts(), (1, 1, 1));

        let _rx4 = channels.subscribe_pool_updates();
        assert_eq!(channels.subscriber_counts(), (2, 1, 1));
    }

    #[test]
    fn test_subscriber_count_decreases_on_drop() {
        let channels = EventChannels::new();

        let rx1 = channels.subscribe_pool_updates();
        let rx2 = channels.subscribe_pool_updates();
        assert_eq!(channels.subscriber_counts().0, 2);

        drop(rx1);
        assert_eq!(channels.subscriber_counts().0, 1);

        drop(rx2);
        assert_eq!(channels.subscriber_counts().0, 0);
    }

    // ── Dispatch without subscribers ──

    #[test]
    fn test_dispatch_pool_update_no_subscribers_does_not_panic() {
        let channels = EventChannels::new();
        channels.dispatch_pool_update(PoolEvent::ReserveUpdate {
            pool: Address::ZERO,
            protocol: aether_common::types::ProtocolType::UniswapV2,
            reserve0: U256::ZERO,
            reserve1: U256::ZERO,
        });
        // Should not panic
    }

    #[test]
    fn test_dispatch_new_block_no_subscribers_does_not_panic() {
        let channels = EventChannels::new();
        channels.dispatch_new_block(NewBlockEvent {
            block_number: 1,
            timestamp: 0,
            base_fee: 0,
            gas_limit: 0,
            ..Default::default()
        });
        // Should not panic
    }

    #[test]
    fn test_dispatch_pending_tx_no_subscribers_does_not_panic() {
        let channels = EventChannels::new();
        channels.dispatch_pending_tx(PendingTxEvent {
            tx_hash: B256::ZERO,
            from: Address::ZERO,
            to: None,
            value: U256::ZERO,
            input: vec![],
            gas_price: 0,
            ..Default::default()
        });
        // Should not panic
    }

    // ── Event struct tests ──

    #[test]
    fn test_new_block_event_clone() {
        let event = NewBlockEvent {
            block_number: 18_000_000,
            timestamp: 1_700_000_000,
            base_fee: 30_000_000_000,
            gas_limit: 30_000_000,
            ..Default::default()
        };
        let cloned = event.clone();
        assert_eq!(cloned.block_number, event.block_number);
        assert_eq!(cloned.timestamp, event.timestamp);
        assert_eq!(cloned.base_fee, event.base_fee);
        assert_eq!(cloned.gas_limit, event.gas_limit);
    }

    #[test]
    fn test_pending_tx_event_clone() {
        let event = PendingTxEvent {
            tx_hash: B256::ZERO,
            from: Address::ZERO,
            to: Some(Address::ZERO),
            value: U256::from(1u64),
            input: vec![0x01, 0x02],
            gas_price: 100,
            raw_tx: vec![0x02, 0x03, 0x04],
            ..Default::default()
        };
        let cloned = event.clone();
        assert_eq!(cloned.tx_hash, event.tx_hash);
        assert_eq!(cloned.input, event.input);
        assert_eq!(cloned.gas_price, event.gas_price);
        assert_eq!(cloned.raw_tx, event.raw_tx);
    }

    #[test]
    fn test_pending_tx_event_to_is_optional() {
        let event = PendingTxEvent {
            tx_hash: B256::ZERO,
            from: Address::ZERO,
            to: None,
            value: U256::ZERO,
            input: vec![],
            gas_price: 0,
            ..Default::default()
        };
        assert!(event.to.is_none());
    }
}

use alloy::primitives::{Address, U256};
use aether_common::types::ProtocolType;
use crate::Pool;

/// Conservative discount on unequal-weight analytical output (2%).
const UNEQUAL_WEIGHT_SAFETY_MARGIN_BPS: u32 = 200;

/// Balancer V2 weighted pool
///
/// Implements the weighted constant product formula:
///   prod(B_i ^ W_i) = k
///
/// For swaps between two tokens:
///   amount_out = B_out * (1 - (B_in / (B_in + amount_in))^(W_in / W_out))
///
/// Equal-weight (50/50) pools simplify to the standard constant product formula.
/// For unequal weights, a first-order approximation is used for gas-efficient
/// estimation. Equal-weight (50/50) pools use exact constant-product math;
/// unequal-weight outputs include implicit conservative bias — escalate to
/// revm simulation when `predict_post_state` returns `analytical = false`.
#[derive(Debug, Clone)]
pub struct BalancerPool {
    pub address: Address,
    pub token0: Address,
    pub token1: Address,
    pub balance0: U256,
    pub balance1: U256,
    pub weight0: U256, // Normalized weight (e.g., 500000 for 50%)
    pub weight1: U256,
    pub fee_bps: u32,
}

/// Snapshot of a Balancer weighted-2-token pool *after* a hypothetical
/// victim swap has been applied. Returned by
/// [`BalancerPool::predict_post_state`] so the mempool post-state simulator
/// can update its graph-edge cache without an RPC round-trip.
///
/// `analytical` is `false` for the unequal-weight branch since
/// `get_amount_out` uses a first-order Taylor approximation there; the
/// caller should escalate those to an EVM fork-replay fallback. The
/// equal-weight branch (50/50, the dominant on-chain shape) is exact and
/// keeps `analytical = true`.
#[derive(Debug, Clone, PartialEq, Eq)]
pub struct BalancerPostState {
    /// `balance0` after the swap settles.
    pub new_balance0: U256,
    /// `balance1` after the swap settles.
    pub new_balance1: U256,
    /// Output amount the swapper receives, post-fee.
    pub amount_out: U256,
    /// `true` for equal-weight pools where the math is exact;
    /// `false` for the first-order approximation used on unequal weights.
    pub analytical: bool,
}

impl BalancerPool {
    pub fn new(
        address: Address,
        token0: Address,
        token1: Address,
        weight0: u64,
        weight1: u64,
        fee_bps: u32,
    ) -> Self {
        Self {
            address,
            token0,
            token1,
            balance0: U256::ZERO,
            balance1: U256::ZERO,
            weight0: U256::from(weight0),
            weight1: U256::from(weight1),
            fee_bps,
        }
    }

    /// Predict the pool's post-swap state under the same weighted-product
    /// math as [`Pool::get_amount_out`]. Used by the mempool post-state
    /// simulator to feed updated balances into the graph-edge cache
    /// without an RPC round-trip.
    ///
    /// Returns `None` when the inputs are invalid: zero amount, unknown
    /// token, or either balance starts at zero. The fee model matches
    /// Balancer's on-chain `Vault`: the fee portion of `amount_in` stays
    /// in the pool, so `new_balance_in = balance_in + amount_in` (the
    /// full input is credited), `new_balance_out = balance_out - amount_out`.
    ///
    /// `analytical` is `true` only on the equal-weight branch where the
    /// math reduces to the exact constant-product formula; the unequal-
    /// weight branch is a first-order Taylor approximation and signals
    /// `false` so the caller can fall back to an EVM fork-replay.
    pub fn predict_post_state(
        &self,
        token_in: Address,
        amount_in: U256,
    ) -> Option<BalancerPostState> {
        if amount_in.is_zero() {
            return None;
        }
        let amount_out = self.get_amount_out(token_in, amount_in)?;
        let analytical = self.weight0 == self.weight1;

        let (new_balance0, new_balance1) = if token_in == self.token0 {
            (
                self.balance0.checked_add(amount_in)?,
                self.balance1.checked_sub(amount_out)?,
            )
        } else if token_in == self.token1 {
            (
                self.balance0.checked_sub(amount_out)?,
                self.balance1.checked_add(amount_in)?,
            )
        } else {
            return None;
        };

        Some(BalancerPostState {
            new_balance0,
            new_balance1,
            amount_out,
            analytical,
        })
    }
}

impl Pool for BalancerPool {
    fn protocol(&self) -> ProtocolType {
        ProtocolType::BalancerV2
    }
    fn address(&self) -> Address {
        self.address
    }
    fn tokens(&self) -> Vec<Address> {
        vec![self.token0, self.token1]
    }
    fn fee_bps(&self) -> u32 {
        self.fee_bps
    }

    fn get_amount_out(&self, token_in: Address, amount_in: U256) -> Option<U256> {
        if amount_in.is_zero() {
            return None;
        }
        let (bal_in, bal_out, w_in, w_out) = if token_in == self.token0 {
            (self.balance0, self.balance1, self.weight0, self.weight1)
        } else if token_in == self.token1 {
            (self.balance1, self.balance0, self.weight1, self.weight0)
        } else {
            return None;
        };
        if bal_in.is_zero() || bal_out.is_zero() {
            return None;
        }

        // Apply fee to input
        let fee_complement = U256::from(10000 - self.fee_bps);
        let amount_in_after_fee = amount_in * fee_complement / U256::from(10000);

        if w_in == w_out {
            // Equal weights: simplifies to constant product
            // amount_out = bal_out * amount_in_after_fee / (bal_in + amount_in_after_fee)
            let numerator = bal_out * amount_in_after_fee;
            let denominator = bal_in + amount_in_after_fee;
            Some(numerator / denominator)
        } else {
            // Weighted formula approximation using first-order Taylor expansion
            // amount_out ~ bal_out * (amount_in_after_fee * w_in) / (bal_in * w_out + amount_in_after_fee * w_in)
            let numerator = bal_out * amount_in_after_fee * w_in;
            let denominator = bal_in * w_out + amount_in_after_fee * w_in;
            if denominator.is_zero() {
                return None;
            }
            let raw = numerator / denominator;
            Some(raw * U256::from(10_000u32 - UNEQUAL_WEIGHT_SAFETY_MARGIN_BPS) / U256::from(10_000u32))
        }
    }

    fn get_amount_in(&self, token_out: Address, amount_out: U256) -> Option<U256> {
        if amount_out.is_zero() {
            return None;
        }
        let (bal_in, bal_out, w_in, w_out) = if token_out == self.token1 {
            (self.balance0, self.balance1, self.weight0, self.weight1)
        } else if token_out == self.token0 {
            (self.balance1, self.balance0, self.weight1, self.weight0)
        } else {
            return None;
        };
        if bal_in.is_zero() || bal_out.is_zero() || amount_out >= bal_out {
            return None;
        }

        if w_in == w_out {
            // Equal weights: constant product inverse
            let numerator = bal_in * amount_out;
            let denominator = bal_out - amount_out;
            let amount_in_before_fee = numerator / denominator + U256::from(1);
            Some(amount_in_before_fee * U256::from(10000) / U256::from(10000 - self.fee_bps))
        } else {
            // Weighted inverse approximation
            let numerator = bal_in * amount_out * w_out;
            let denominator = (bal_out - amount_out) * w_in;
            if denominator.is_zero() {
                return None;
            }
            let amount_in_before_fee = numerator / denominator + U256::from(1);
            Some(amount_in_before_fee * U256::from(10000) / U256::from(10000 - self.fee_bps))
        }
    }

    fn update_state(&mut self, reserve0: U256, reserve1: U256) {
        self.balance0 = reserve0;
        self.balance1 = reserve1;
    }

    fn encode_swap(&self, token_in: Address, amount_in: U256, min_out: U256) -> Vec<u8> {
        let token_out = if token_in == self.token0 {
            self.token1
        } else if token_in == self.token1 {
            self.token0
        } else {
            return Vec::new();
        };
        crate::swap_encode::encode_balancer_vault_swap(
            self.address,
            token_in,
            token_out,
            amount_in,
            min_out,
        )
    }

    fn liquidity_depth(&self) -> U256 {
        std::cmp::min(self.balance0, self.balance1)
    }
}

#[cfg(test)]
mod tests {
    use super::*;
    use alloy::primitives::address;

    fn setup_balancer_pool() -> BalancerPool {
        let mut pool = BalancerPool::new(
            Address::ZERO,
            address!("C02aaA39b223FE8D0A0e5C4F27eAD9083C756Cc2"), // WETH
            address!("A0b86991c6218b36c1d19D4a2e9Eb0cE3606eB48"), // USDC
            500000,
            500000, // 50/50 weights
            30,     // 0.3% fee
        );
        pool.update_state(
            U256::from(5_000_000_000_000_000_000_000u128), // 5000 ETH
            U256::from(10_000_000_000_000u64),             // 10M USDC
        );
        pool
    }

    #[test]
    fn test_balancer_equal_weight() {
        let pool = setup_balancer_pool();
        let eth_in = U256::from(1_000_000_000_000_000_000u64); // 1 ETH
        let out = pool.get_amount_out(pool.token0, eth_in).unwrap();
        assert!(!out.is_zero());
    }

    #[test]
    fn test_balancer_protocol() {
        let pool = setup_balancer_pool();
        assert_eq!(pool.protocol(), ProtocolType::BalancerV2);
    }

    #[test]
    fn test_balancer_inverse_round_trip_equal_weight() {
        let pool = setup_balancer_pool();
        let amount_in = U256::from(1_000_000_000_000_000_000u64);
        let amount_out = pool.get_amount_out(pool.token0, amount_in).unwrap();
        let amount_in_back = pool.get_amount_in(pool.token1, amount_out).unwrap();
        assert!(amount_in_back <= amount_in);
        assert!(
            amount_in_back >= amount_in * U256::from(95u64) / U256::from(100u64),
            "equal-weight inverse should be within 5% (fee + approximation)"
        );
    }

    #[test]
    fn unequal_weight_applies_safety_margin() {
        let pool = setup_balancer_80_20_pool();
        let amount_in = U256::from(1_000_000_000_000_000_000u64);
        let w_in = pool.weight0;
        let w_out = pool.weight1;
        let fee_complement = U256::from(10_000 - pool.fee_bps);
        let amount_in_after_fee = amount_in * fee_complement / U256::from(10_000);
        let numerator = pool.balance1 * amount_in_after_fee * w_in;
        let denominator = pool.balance0 * w_out + amount_in_after_fee * w_in;
        let raw = numerator / denominator;
        let out = pool.get_amount_out(pool.token0, amount_in).unwrap();
        let expected = raw * U256::from(10_000u32 - UNEQUAL_WEIGHT_SAFETY_MARGIN_BPS) / U256::from(10_000u32);
        assert_eq!(out, expected);
    }

    fn setup_balancer_80_20_pool() -> BalancerPool {
        let mut pool = BalancerPool::new(
            Address::ZERO,
            address!("C02aaA39b223FE8D0A0e5C4F27eAD9083C756Cc2"), // WETH
            address!("A0b86991c6218b36c1d19D4a2e9Eb0cE3606eB48"), // USDC
            200000, 800000, // 20/80 weights — unequal, exercises approx path
            10,             // 0.1%
        );
        pool.update_state(
            U256::from(1_000_000_000_000_000_000_000u128),
            U256::from(10_000_000_000_000u64),
        );
        pool
    }

    // ----- predict_post_state -----

    #[test]
    fn predict_post_state_none_for_zero_amount() {
        let pool = setup_balancer_pool();
        assert!(pool.predict_post_state(pool.token0, U256::ZERO).is_none());
    }

    #[test]
    fn predict_post_state_none_for_unknown_token() {
        let pool = setup_balancer_pool();
        let bogus = address!("0000000000000000000000000000000000001234");
        assert!(pool.predict_post_state(bogus, U256::from(1u64)).is_none());
    }

    #[test]
    fn predict_post_state_none_for_uninitialised_pool() {
        let pool = BalancerPool::new(
            Address::ZERO,
            address!("C02aaA39b223FE8D0A0e5C4F27eAD9083C756Cc2"),
            address!("A0b86991c6218b36c1d19D4a2e9Eb0cE3606eB48"),
            500000, 500000, 30,
        );
        assert!(pool
            .predict_post_state(pool.token0, U256::from(1u64))
            .is_none());
    }

    #[test]
    fn predict_post_state_balances_shift_correctly_equal_weight() {
        let pool = setup_balancer_pool();
        let dx = U256::from(1_000_000_000_000_000_000u64); // 1 ETH
        let post = pool
            .predict_post_state(pool.token0, dx)
            .expect("post state");
        assert_eq!(post.new_balance0, pool.balance0 + dx);
        assert_eq!(post.new_balance1, pool.balance1 - post.amount_out);
        assert!(post.analytical, "50/50 pool is exact, analytical=true");
    }

    #[test]
    fn predict_post_state_unequal_weight_signals_approximation() {
        let pool = setup_balancer_80_20_pool();
        let dx = U256::from(1_000_000_000_000_000_000u64);
        let post = pool
            .predict_post_state(pool.token0, dx)
            .expect("post state");
        assert!(
            !post.analytical,
            "20/80 pool uses first-order approximation, analytical=false"
        );
    }

    #[test]
    fn predict_post_state_amount_out_matches_get_amount_out() {
        let pool = setup_balancer_pool();
        for amt in [
            U256::from(1_000_000_000u64),
            U256::from(1_000_000_000_000_000_000u64),
            U256::from(10_000_000_000_000_000_000u64),
        ] {
            let legacy = pool
                .get_amount_out(pool.token0, amt)
                .expect("legacy amount_out");
            let post = pool
                .predict_post_state(pool.token0, amt)
                .expect("post state");
            assert_eq!(
                post.amount_out, legacy,
                "predict_post_state diverged from get_amount_out at amt={amt}"
            );
        }
    }

    #[test]
    fn predict_post_state_reverse_direction() {
        let pool = setup_balancer_pool();
        let dx = U256::from(1_000_000_000u64);
        let post = pool
            .predict_post_state(pool.token1, dx)
            .expect("post state");
        assert_eq!(post.new_balance0, pool.balance0 - post.amount_out);
        assert_eq!(post.new_balance1, pool.balance1 + dx);
    }

    #[test]
    fn test_balancer_zero_balance_error() {
        let pool = BalancerPool::new(
            Address::ZERO,
            address!("C02aaA39b223FE8D0A0e5C4F27eAD9083C756Cc2"),
            address!("A0b86991c6218b36c1d19D4a2e9Eb0cE3606eB48"),
            500000,
            500000,
            30,
        );
        assert!(pool
            .get_amount_out(pool.token0, U256::from(1000u64))
            .is_none());
    }

    #[test]
    fn test_balancer_invalid_token_error() {
        let pool = setup_balancer_pool();
        assert!(pool
            .get_amount_out(Address::repeat_byte(0xcd), U256::from(1000u64))
            .is_none());
    }

    #[test]
    fn test_balancer_get_amount_in_overflow_reserve() {
        let pool = setup_balancer_pool();
        assert!(pool
            .get_amount_in(pool.token1, pool.balance1)
            .is_none());
    }

    #[test]
    fn test_balancer_unequal_weight_huge_input() {
        let pool = setup_balancer_80_20_pool();
        let out = pool
            .get_amount_out(
                pool.token0,
                U256::from(10u128.pow(30)),
            )
            .expect("approx path");
        assert!(out < pool.balance1);
    }
}

//! Balancer V3 pool adapter.
//!
//! Balancer V3 pools hold ERC-20 balances directly on the pool contract
//! (no Vault indirection). For analytical validation and scoring we reuse
//! the equal-weight constant-product math from [`BalancerPool`] with a
//! 5% safety margin on output estimates. Full tick-accurate V3 math and
//! on-chain router calldata are handled by the discovery validator and
//! executor `step.data` respectively.

use alloy::primitives::{Address, U256};
use aether_common::types::ProtocolType;

use crate::balancer::{BalancerPool, BalancerPostState};
use crate::swap_encode;
use crate::Pool;

/// Safety margin applied to analytical `get_amount_out` (5%).
const SAFETY_MARGIN_BPS: u32 = 500;

/// Balancer V3 weighted pool — analytical adapter for discovery and hot-cache.
#[derive(Debug, Clone)]
pub struct BalancerV3Pool {
    inner: BalancerPool,
}

impl BalancerV3Pool {
    pub fn new(
        address: Address,
        token0: Address,
        token1: Address,
        weight0: u64,
        weight1: u64,
        fee_bps: u32,
    ) -> Self {
        Self {
            inner: BalancerPool::new(address, token0, token1, weight0, weight1, fee_bps),
        }
    }

    pub fn predict_post_state(
        &self,
        token_in: Address,
        amount_in: U256,
    ) -> Option<BalancerPostState> {
        self.inner.predict_post_state(token_in, amount_in)
    }

    fn apply_safety_margin(amount: U256) -> U256 {
        amount * U256::from(10_000u32 - SAFETY_MARGIN_BPS) / U256::from(10_000u32)
    }
}

impl Pool for BalancerV3Pool {
    fn protocol(&self) -> ProtocolType {
        ProtocolType::BalancerV3
    }

    fn address(&self) -> Address {
        self.inner.address
    }

    fn tokens(&self) -> Vec<Address> {
        vec![self.inner.token0, self.inner.token1]
    }

    fn fee_bps(&self) -> u32 {
        self.inner.fee_bps
    }

    fn get_amount_out(&self, token_in: Address, amount_in: U256) -> Option<U256> {
        self.inner
            .get_amount_out(token_in, amount_in)
            .map(Self::apply_safety_margin)
    }

    fn get_amount_in(&self, token_out: Address, amount_out: U256) -> Option<U256> {
        self.inner.get_amount_in(token_out, amount_out)
    }

    fn update_state(&mut self, reserve0: U256, reserve1: U256) {
        self.inner.update_state(reserve0, reserve1);
    }

    fn encode_swap(&self, token_in: Address, amount_in: U256, min_out: U256) -> Vec<u8> {
        let token_out = if token_in == self.inner.token0 {
            self.inner.token1
        } else if token_in == self.inner.token1 {
            self.inner.token0
        } else {
            return Vec::new();
        };
        swap_encode::encode_balancer_vault_swap(
            self.inner.address,
            token_in,
            token_out,
            amount_in,
            min_out,
        )
    }

    fn liquidity_depth(&self) -> U256 {
        self.inner.liquidity_depth()
    }
}

