            U256::from(2_000_000_000_000_000_000_000u128), // 2000 BNT
        );
        pool
    }

    fn link_bnt_pool() -> BancorPool {
        let mut pool = BancorPool::new(
            address!("aaaa000000000000000000000000000000000002"),
            link_address(),
            BNT_ADDRESS,
            30,
        );
        pool.update_state(
            U256::from(500_000_000_000_000_000_000u128), // 500 LINK
            U256::from(1_500_000_000_000_000_000_000u128), // 1500 BNT
        );
        pool
    }

    #[test]
    fn multihop_happy_path_returns_two_aligned_post_states() {
        let leg_a_pool = weth_bnt_pool();
        let leg_b_pool = link_bnt_pool();
        let amount_in = U256::from(10_000_000_000_000_000_000u128); // 10 WETH

        let (leg_a, leg_b) = leg_a_pool
            .predict_post_state_multihop(weth_address(), amount_in, link_address(), &leg_b_pool)
            .expect("multihop predictor returns Some");

        // Leg A: WETH-in, BNT-out → new_balance_in tracks WETH side,
        // new_balance_out tracks BNT side.
        assert!(leg_a.analytical);
        assert_eq!(leg_a.new_balance_in, leg_a_pool.token_balance + amount_in);
        assert_eq!(leg_a.new_balance_out, leg_a_pool.bnt_balance - leg_a.amount_out);

        // Leg B: BNT-in, LINK-out → new_balance_in tracks BNT side,
        // new_balance_out tracks LINK side. Intermediate amount equals
        // leg A's amount_out.
        assert!(leg_b.analytical);
        assert_eq!(leg_b.new_balance_in, leg_b_pool.bnt_balance + leg_a.amount_out);
        assert_eq!(leg_b.new_balance_out, leg_b_pool.token_balance - leg_b.amount_out);
        assert!(leg_b.amount_out > U256::ZERO);
    }

    #[test]
    fn multihop_returns_none_when_token_in_is_bnt() {
        // If `token_in == BNT` this is a single-leg swap that belongs on
        // `predict_post_state`, not on the multi-hop helper.
        let leg_a_pool = weth_bnt_pool();
        let leg_b_pool = link_bnt_pool();
        let amount_in = U256::from(1_000_000_000_000_000_000u128);
        assert!(leg_a_pool
            .predict_post_state_multihop(BNT_ADDRESS, amount_in, link_address(), &leg_b_pool)
            .is_none());
    }

    #[test]
    fn multihop_returns_none_when_token_out_is_bnt() {
        // Mirror of the above: BNT on the output side is single-leg.
        let leg_a_pool = weth_bnt_pool();
        let leg_b_pool = link_bnt_pool();
        let amount_in = U256::from(1_000_000_000_000_000_000u128);
        assert!(leg_a_pool
            .predict_post_state_multihop(weth_address(), amount_in, BNT_ADDRESS, &leg_b_pool)
            .is_none());
    }

    #[test]
    fn multihop_returns_none_when_leg_a_pool_mismatches_token_in() {
        // `self` must pair against `token_in`. Passing the LINK/BNT pool
        // as leg A while asking for a WETH-in swap must bail rather than
        // silently emit a wrong post-state.
        let leg_a_pool = link_bnt_pool();
        let leg_b_pool = link_bnt_pool();
        let amount_in = U256::from(1_000_000_000_000_000_000u128);
        assert!(leg_a_pool
            .predict_post_state_multihop(weth_address(), amount_in, link_address(), &leg_b_pool)
            .is_none());
    }

    #[test]
    fn multihop_returns_none_when_leg_b_pool_mismatches_token_out() {
        let leg_a_pool = weth_bnt_pool();
        // Second pool also says "WETH" on its non-BNT side → wrong pool
        // for a swap whose `token_out` is LINK.
        let leg_b_pool = weth_bnt_pool();
        let amount_in = U256::from(1_000_000_000_000_000_000u128);
        assert!(leg_a_pool
            .predict_post_state_multihop(weth_address(), amount_in, link_address(), &leg_b_pool)
            .is_none());
    }

    #[test]
    fn multihop_returns_none_when_either_pool_has_non_canonical_bnt() {
        // Defensive check: pool whose `bnt` field drifted from the canonical
        // BNT address. Without this guard the predictor would happily run
        // the math and produce "BNT-denominated" intermediate amounts in a
        // different token, corrupting downstream graph edges.
        let mut leg_a_pool = weth_bnt_pool();
        leg_a_pool.bnt = address!("dddddddddddddddddddddddddddddddddddddddd");
        let leg_b_pool = link_bnt_pool();
        let amount_in = U256::from(1_000_000_000_000_000_000u128);
        assert!(leg_a_pool
            .predict_post_state_multihop(weth_address(), amount_in, link_address(), &leg_b_pool)
            .is_none());

        let leg_a_pool = weth_bnt_pool();
        let mut leg_b_pool = link_bnt_pool();
        leg_b_pool.bnt = address!("dddddddddddddddddddddddddddddddddddddddd");
        assert!(leg_a_pool
            .predict_post_state_multihop(weth_address(), amount_in, link_address(), &leg_b_pool)
            .is_none());
    }

    #[test]
    fn multihop_returns_none_when_leg_a_predictor_bails() {
        // Empty reserves on leg A → first `predict_post_state` returns
        // None → no second-leg call.
        let leg_a_pool = BancorPool::new(
            Address::ZERO,
            weth_address(),
            BNT_ADDRESS,
            30,
        );
        let leg_b_pool = link_bnt_pool();
        let amount_in = U256::from(1_000_000_000_000_000_000u128);
        assert!(leg_a_pool
            .predict_post_state_multihop(weth_address(), amount_in, link_address(), &leg_b_pool)
            .is_none());
    }

    #[test]
    fn test_bancor_zero_reserves_error() {
        let pool = BancorPool::new(
            Address::ZERO,
            weth_address(),
            BNT_ADDRESS,
            30,
        );
        assert!(pool.get_amount_out(weth_address(), U256::from(1000u64)).is_none());
    }

    #[test]
    fn test_bancor_invalid_token_error() {
        let pool = seeded_pool();
        assert!(pool
            .get_amount_out(Address::repeat_byte(0xef), U256::from(1000u64))
            .is_none());
    }

    #[test]
    fn test_bancor_get_amount_in_exceeds_reserve() {
        let pool = seeded_pool();
        assert!(pool
            .get_amount_in(pool.bnt, pool.bnt_balance)
            .is_none());
    }

    #[test]
    fn test_bancor_huge_swap_bounded_by_reserve() {
        let pool = seeded_pool();
        let out = pool
            .get_amount_out(pool.token, U256::from(10u128.pow(30)))
            .expect("bonding curve");
        assert!(out < pool.bnt_balance);
    }
}

use alloy::primitives::{Address, U256};
use aether_common::types::ProtocolType;
use crate::Pool;

/// Curve StableSwap pool (2-token variant)
///
/// Implements the StableSwap invariant:
///   A * n^n * sum(x_i) + D = A * n^n * D + D^(n+1) / (n^n * prod(x_i))
///
/// Newton's method is used to solve for D and y, exactly matching the
/// on-chain Solidity implementation in Curve's StableSwap contracts.
///
/// **Limitation:** Only 2-coin pools are supported. 3+ coin pools are not
/// discovered by the factory listener and are excluded from the hot cache.
#[derive(Debug, Clone)]
pub struct CurvePool {
    pub address: Address,
    pub tokens: Vec<Address>,
    pub balances: Vec<U256>,
    pub amplification: U256, // A coefficient
    pub fee_bps: u32,        // typically 4 (0.04%)
}

/// Snapshot of a Curve 2-coin pool *after* a hypothetical victim swap
/// has been applied. Returned by [`CurvePool::predict_post_state`] so the
/// mempool post-state simulator can update its graph-edge cache without
/// round-tripping to RPC.
///
/// The post-balances reflect the pool's view *after* the swap settles:
/// balance_in grew by the full input, balance_out fell by the user-
/// visible output, and the fee is implicitly retained in the pool (which
/// is why `new_balance_out > y_new` in Curve's accounting).
///
/// `analytical` mirrors the V3 `single_tick` flag: `true` when the
/// Newton iteration converged on a valid post-state and the math is
/// trustworthy. `false` triggers the EVM fork-replay fallback.
#[derive(Debug, Clone, PartialEq, Eq)]
pub struct CurvePostState {
    /// Index in `pool.tokens` of the input token.
    pub i: usize,
    /// Index in `pool.tokens` of the output token.
    pub j: usize,
    /// `pool.balances[i]` after the swap settles (= prev + amount_in).
    pub new_balance_in: U256,
    /// `pool.balances[j]` after the swap settles. Equals
    /// `prev - amount_out` (fee retained in pool).
    pub new_balance_out: U256,
    /// Output amount the swapper receives, post-fee.
    pub amount_out: U256,
    /// `true` when Newton converged on a valid post-state and the
    /// analytical answer is trustworthy. `false` signals an EVM fork-
    /// replay fallback to the caller.
    pub analytical: bool,
}

impl CurvePool {
    pub fn new(address: Address, tokens: Vec<Address>, amplification: u64, fee_bps: u32) -> Self {
        let n = tokens.len();
        Self {
            address,
            tokens,
            balances: vec![U256::ZERO; n],
            amplification: U256::from(amplification),
            fee_bps,
        }
    }

    /// Compute StableSwap invariant D using Newton's method.
    ///
    /// The invariant is: A * n^n * S + D = A * n^n * D + D^(n+1) / (n^n * prod(x_i))
    /// where S = sum(x_i).
    ///
    /// Newton iteration:
    ///   d_new = (A*n^n*S + n*D_P) * D / ((A*n^n - 1)*D + (n+1)*D_P)
    ///   where D_P = D^(n+1) / (n^n * prod(x_i))
    fn get_d(&self) -> U256 {
        let n = U256::from(self.balances.len());
        let mut s = U256::ZERO;
        for b in &self.balances {
            s += *b;
        }
        if s.is_zero() {
            return U256::ZERO;
        }

        let ann = self.amplification * n;
        let mut d = s;

        for _ in 0..256 {
            let mut d_p = d;
            for b in &self.balances {
                if b.is_zero() {
                    return U256::ZERO;
                }
                // d_p = d_p * d / (b * n)
                d_p = d_p * d / (*b * n);
            }
            let d_prev = d;
            // d = (ann * s + d_p * n) * d / ((ann - 1) * d + (n + 1) * d_p)
            let numerator = (ann * s + d_p * n) * d;
            let denominator = (ann - U256::from(1)) * d + (n + U256::from(1)) * d_p;
            if denominator.is_zero() {
                return d;
            }
            d = numerator / denominator;

            // Convergence check (within 1 wei)
            if d > d_prev {
                if d - d_prev <= U256::from(1) {
                    break;
                }
            } else if d_prev - d <= U256::from(1) {
                break;
            }
        }
        d
    }

    /// Predict the pool's post-swap state under the same StableSwap
    /// Newton iteration as [`Pool::get_amount_out`]. Used by the mempool
    /// post-state simulator to feed updated balances into the graph edge
    /// cache without an RPC round-trip.
    ///
    /// Returns `None` when the inputs are invalid: zero amount, unknown
    /// token, fewer than 2 coins, swap would drain a balance to zero, or
    /// Newton fails to converge to a smaller `balance_out`. The fee
    /// retention model matches Curve's on-chain `StableSwap` contract:
    /// `new_balance_in = balances[i] + amount_in`,
    /// `new_balance_out = balances[j] - amount_out`. The pool keeps the
    /// fee, which is why the post-balance is *higher* than the Newton-
    /// solved `y`.
    pub fn predict_post_state(
        &self,
        token_in: Address,
        amount_in: U256,
    ) -> Option<CurvePostState> {
        if amount_in.is_zero() {
            return None;
        }
        if self.balances.len() < 2 {
            return None;
        }
        let i = self.tokens.iter().position(|t| *t == token_in)?;
        // 2-coin variant: output is the other index. Generalising to 3+
        // coins requires the caller to pick j explicitly; pinned at
        // 2-coin here to match the existing `Pool::get_amount_out`.
        if self.tokens.len() != 2 {
            return None;
        }
        let j = if i == 0 { 1 } else { 0 };

        let new_balance_in = self.balances[i].checked_add(amount_in)?;
        let y_new = self.get_y(i, j, new_balance_in)?;
        // dy is what the pool owes before fee — Newton can briefly
        // overshoot in the reverse direction so guard with checked_sub.
        let dy = self.balances[j].checked_sub(y_new)?;
        if dy.is_zero() {
            return None;
        }
        // Fee is taken out of the user's payout, retained in the pool.
        let fee = dy * U256::from(self.fee_bps) / U256::from(10_000u64);
        let amount_out = dy.checked_sub(fee)?;
        let new_balance_out = self.balances[j].checked_sub(amount_out)?;

        Some(CurvePostState {
            i,
            j,
            new_balance_in,
            new_balance_out,
            amount_out,
            analytical: true,
        })
    }

    /// Get y given x for the StableSwap invariant.
    ///
    /// Solves for y in the invariant equation, holding all other balances constant
    /// except for x_i (which is set to `x`) and x_j (which we solve for).
    fn get_y(&self, i: usize, j: usize, x: U256) -> Option<U256> {
        let n = self.balances.len();
        if i >= n || j >= n || i == j {
            return None;
        }

        let d = self.get_d();
        if d.is_zero() {
            return None;
        }

        let n_u256 = U256::from(n);
        let ann = self.amplification * n_u256;

        let mut s = x;
        let mut c = d * d / (x * n_u256);
        for k in 0..n {
            if k == i || k == j {
                continue;
            }
            s += self.balances[k];
            c = c * d / (self.balances[k] * n_u256);
        }
        c = c * d / (ann * n_u256);
        let b = s + d / ann;

        let mut y = d;
        for _ in 0..256 {
            let y_prev = y;
            // y = (y^2 + c) / (2*y + b - d)
            y = (y * y + c) / (U256::from(2) * y + b - d);
            if y > y_prev {
                if y - y_prev <= U256::from(1) {
                    break;
                }
            } else if y_prev - y <= U256::from(1) {
                break;
            }
        }
        Some(y)
    }
}

impl Pool for CurvePool {
    fn protocol(&self) -> ProtocolType {
        ProtocolType::Curve
    }
    fn address(&self) -> Address {
        self.address
    }
    fn tokens(&self) -> Vec<Address> {
        self.tokens.clone()
    }
    fn fee_bps(&self) -> u32 {
        self.fee_bps
    }

    fn get_amount_out(&self, token_in: Address, amount_in: U256) -> Option<U256> {
        if amount_in.is_zero() {
            return None;
        }
        if self.tokens.len() > 2 {
            tracing::warn!(
                pool = %self.address,
                coins = self.tokens.len(),
                "Curve 3+ coin pool — analytical adapter unsupported; use revm simulation"
            );
            return None;
        }
        let i = self.tokens.iter().position(|t| *t == token_in)?;
        // For 2-token pools, output token is the other one
        let j = if i == 0 { 1 } else { 0 };

        let x = self.balances[i] + amount_in;
        let y = self.get_y(i, j, x)?;
        let dy = self.balances[j].checked_sub(y)?;
        if dy.is_zero() {
            return None;
        }

        // Apply fee: fee is taken from the output amount
        let fee = dy * U256::from(self.fee_bps) / U256::from(10000);
        Some(dy - fee)
    }

    fn get_amount_in(&self, token_out: Address, amount_out: U256) -> Option<U256> {
        if amount_out.is_zero() {
            return None;
        }
        let j = self.tokens.iter().position(|t| *t == token_out)?;
        let i = if j == 0 { 1 } else { 0 };

        // Reverse the fee to get the pre-fee output amount
        let amount_out_before_fee =
            amount_out * U256::from(10000) / U256::from(10000 - self.fee_bps);
        let y_new = self.balances[j].checked_sub(amount_out_before_fee)?;

        // Solve for x given y (swap i and j roles in get_y)
        let x = self.get_y(j, i, y_new)?;
        let dx = x.checked_sub(self.balances[i])?;
        Some(dx + U256::from(1))
    }

    fn update_state(&mut self, reserve0: U256, reserve1: U256) {
        if self.balances.len() >= 2 {
            self.balances[0] = reserve0;
            self.balances[1] = reserve1;
        }
    }

    fn encode_swap(&self, token_in: Address, amount_in: U256, min_out: U256) -> Vec<u8> {
        crate::swap_encode::encode_curve_exchange(token_in, &self.tokens, amount_in, min_out)
    }

    fn liquidity_depth(&self) -> U256 {
        self.balances.iter().fold(U256::ZERO, |acc, b| acc + *b)
    }
}

