use alloy::primitives::{Address, U256};
use aether_common::types::SimulationResult;
use fork::{ForkedState, RpcDB, RpcForkedState, SimConfig};
use revm::context::result::ExecutionResult;
use revm::context::{BlockEnv, TxEnv};
use revm::database::{CacheDB, EmptyDBTyped};
use revm::handler::{ExecuteEvm, MainBuilder};
use revm::primitives::hardfork::SpecId;
use revm::state::AccountInfo;
use revm::Context;
use tracing::{debug, error, info};

type SimDB = CacheDB<EmptyDBTyped<std::convert::Infallible>>;

/// EVM Simulator using revm for transaction simulation.
///
/// Simulates transactions against a forked EVM state (CacheDB + EmptyDB)
/// before submitting bundles on-chain. This allows validating arbitrage
/// profitability and catching reverts before spending gas.
pub struct EvmSimulator {
    config: SimConfig,
}

impl EvmSimulator {
    pub fn new(config: SimConfig) -> Self {
        Self { config }
    }

    pub fn with_defaults() -> Self {
        Self::new(SimConfig::default())
    }

    /// Return a reference to the simulator's configuration.
    pub fn config(&self) -> &SimConfig {
        &self.config
    }

    /// Simulate a transaction on forked state.
    /// Returns SimulationResult with success/failure, gas used, and profit info.
    pub fn simulate(
        &self,
        state: &ForkedState,
        to: Address,
        calldata: Vec<u8>,
    ) -> SimulationResult {
        // Clone the DB for simulation (we don't want to mutate the original)
        let db = state.db.clone();

        // Build the block environment
        let block = BlockEnv {
            number: U256::from(state.block_number),
            timestamp: U256::from(state.block_timestamp),
            basefee: state.base_fee,
            ..Default::default()
        };

        // Build the transaction
        let tx = TxEnv::builder()
            .caller(self.config.caller)
            .kind(revm::primitives::TxKind::Call(to))
            .data(revm::primitives::Bytes::copy_from_slice(&calldata))
            .value(self.config.value)
            .gas_limit(self.config.gas_limit)
            .gas_price(state.base_fee as u128)
            .nonce(0)
            .chain_id(Some(state.chain_id))
            .build_fill();

        // Build the context and EVM
        let ctx = Context::<BlockEnv, TxEnv, _, SimDB, revm::context::Journal<SimDB>, ()>::new(db, SpecId::CANCUN)
            .with_block(block)
            .modify_cfg_chained(|cfg| {
                cfg.chain_id = state.chain_id;
                cfg.disable_nonce_check = true;
            });

        let mut evm = ctx.build_mainnet();

        // Execute the transaction
        match evm.transact(tx) {
            Ok(result_and_state) => {
                match result_and_state.result {
                    ExecutionResult::Success {
                        gas_used, output: _, ..
                    } => {
                        debug!(gas_used, "Simulation succeeded");
                        SimulationResult {
                            success: true,
                            profit_wei: U256::ZERO, // Profit calculated externally from balance diff
                            gas_used,
                            revert_reason: None,
                        }
                    }
                    ExecutionResult::Revert { gas_used, output } => {
                        let reason = format!("0x{}", alloy::hex::encode(&output));
                        debug!(gas_used, reason = %reason, "Simulation reverted");
                        SimulationResult {
                            success: false,
                            profit_wei: U256::ZERO,
                            gas_used,
                            revert_reason: Some(reason),
                        }
                    }
                    ExecutionResult::Halt { reason, gas_used } => {
                        let reason_str = format!("{:?}", reason);
                        debug!(gas_used, reason = %reason_str, "Simulation halted");
                        SimulationResult {
                            success: false,
                            profit_wei: U256::ZERO,
                            gas_used,
                            revert_reason: Some(reason_str),
                        }
                    }
                }
            }
            Err(e) => {
                error!(error = %e, "EVM transact error");
                SimulationResult {
                    success: false,
                    profit_wei: U256::ZERO,
                    gas_used: 0,
                    revert_reason: Some(format!("EVM error: {}", e)),
                }
            }
        }
    }

    /// Simulate a transaction and also return the final state diff,
    /// useful for calculating profit from balance changes.
    pub fn simulate_with_profit(
        &self,
        state: &ForkedState,
        to: Address,
        calldata: Vec<u8>,
        _profit_token: Address,
        profit_recipient: Address,
    ) -> SimulationResult {
        // Clone the DB for simulation
        let db = state.db.clone();

        // Record the initial balance of the profit recipient
        let initial_balance = db
            .cache
            .accounts
            .get(&profit_recipient)
            .and_then(|acc| acc.info())
            .map(|info| info.balance)
            .unwrap_or(U256::ZERO);

        // Build the block environment
        let block = BlockEnv {
            number: U256::from(state.block_number),
            timestamp: U256::from(state.block_timestamp),
            basefee: state.base_fee,
            ..Default::default()
        };

        // Build the transaction
        let tx = TxEnv::builder()
            .caller(self.config.caller)
            .kind(revm::primitives::TxKind::Call(to))
            .data(revm::primitives::Bytes::copy_from_slice(&calldata))
            .value(self.config.value)
            .gas_limit(self.config.gas_limit)
            .gas_price(state.base_fee as u128)
            .nonce(0)
            .chain_id(Some(state.chain_id))
            .build_fill();

        // Build the context and EVM
        let ctx = Context::<BlockEnv, TxEnv, _, SimDB, revm::context::Journal<SimDB>, ()>::new(db, SpecId::CANCUN)
            .with_block(block)
            .modify_cfg_chained(|cfg| {
                cfg.chain_id = state.chain_id;
                cfg.disable_nonce_check = true;
            });

        let mut evm = ctx.build_mainnet();

        match evm.transact(tx) {
            Ok(result_and_state) => {
                match result_and_state.result {
                    ExecutionResult::Success { gas_used, .. } => {
                        // Calculate profit from state diff
                        let final_balance = result_and_state
                            .state
                            .get(&profit_recipient)
                            .map(|acc| acc.info.balance)
                            .unwrap_or(initial_balance);

                        let profit = final_balance.saturating_sub(initial_balance);

                        info!(gas_used, %profit, "Simulation succeeded with profit calculation");

                        SimulationResult {
                            success: true,
                            profit_wei: profit,
                            gas_used,
                            revert_reason: None,
                        }
                    }
                    ExecutionResult::Revert { gas_used, output } => {
                        let reason = format!("0x{}", alloy::hex::encode(&output));
                        debug!(gas_used, reason = %reason, "Simulation reverted");
                        SimulationResult {
                            success: false,
                            profit_wei: U256::ZERO,
                            gas_used,
                            revert_reason: Some(reason),
                        }
                    }
                    ExecutionResult::Halt { reason, gas_used } => {
                        let reason_str = format!("{:?}", reason);
                        debug!(gas_used, reason = %reason_str, "Simulation halted");
                        SimulationResult {
                            success: false,
                            profit_wei: U256::ZERO,
                            gas_used,
                            revert_reason: Some(reason_str),
                        }
                    }
                }
            }
            Err(e) => {
                error!(error = %e, "EVM transact error");
                SimulationResult {
                    success: false,
                    profit_wei: U256::ZERO,
                    gas_used: 0,
                    revert_reason: Some(format!("EVM error: {}", e)),
                }
            }
        }
    }

    /// Simulate a transaction against a real RPC-backed fork state.
    ///
    /// Takes ownership of `RpcForkedState` because the underlying `AlloyDB`
    /// is not `Clone`. Creating a new `RpcForkedState` per simulation is cheap
    /// since the provider is `Arc`-wrapped internally.
    pub fn simulate_rpc(
        &self,
        state: RpcForkedState,
        to: Address,
        calldata: Vec<u8>,
    ) -> SimulationResult {
        let block = BlockEnv {
            number: U256::from(state.block_number),
            timestamp: U256::from(state.block_timestamp),
            basefee: state.base_fee,
            ..Default::default()
        };

        let tx = TxEnv::builder()
            .caller(self.config.caller)
            .kind(revm::primitives::TxKind::Call(to))
            .data(revm::primitives::Bytes::copy_from_slice(&calldata))
            .value(self.config.value)
            .gas_limit(self.config.gas_limit)
            .gas_price(state.base_fee as u128)
            .nonce(0)
            .chain_id(Some(state.chain_id))
            .build_fill();

        let ctx = Context::<BlockEnv, TxEnv, _, RpcDB, revm::context::Journal<RpcDB>, ()>::new(
            state.db,
            SpecId::CANCUN,
        )
        .with_block(block)
        .modify_cfg_chained(|cfg| {
            cfg.chain_id = state.chain_id;
            cfg.disable_nonce_check = true;
        });

        let mut evm = ctx.build_mainnet();

        match evm.transact(tx) {
            Ok(result_and_state) => match result_and_state.result {
                ExecutionResult::Success {
                    gas_used, output: _, ..
                } => {
                    debug!(gas_used, "RPC simulation succeeded");
                    SimulationResult {
                        success: true,
                        profit_wei: U256::ZERO,
                        gas_used,
                        revert_reason: None,
                    }
                }
                ExecutionResult::Revert { gas_used, output } => {
                    let reason = format!("0x{}", alloy::hex::encode(&output));
                    debug!(gas_used, reason = %reason, "RPC simulation reverted");
                    SimulationResult {
                        success: false,
                        profit_wei: U256::ZERO,
                        gas_used,
                        revert_reason: Some(reason),
                    }
                }
                ExecutionResult::Halt { reason, gas_used } => {
                    let reason_str = format!("{:?}", reason);
                    debug!(gas_used, reason = %reason_str, "RPC simulation halted");
                    SimulationResult {
                        success: false,
                        profit_wei: U256::ZERO,
                        gas_used,
                        revert_reason: Some(reason_str),
                    }
                }
            },
            Err(e) => {
                error!(error = %e, "RPC EVM transact error");
                SimulationResult {
                    success: false,
                    profit_wei: U256::ZERO,
                    gas_used: 0,
                    revert_reason: Some(format!("EVM error: {}", e)),
                }
            }
        }
    }

    /// Deploy a contract via CREATE and then CALL it, measuring the ERC20
    /// balance delta on `profit_recipient` for `profit_token` as profit.
    ///
    /// Two `transact` calls on the same revm `Context` share state: the
    /// deployed contract's runtime bytecode is visible to the second CALL.
    /// This lets us deploy AetherExecutor and immediately invoke
    /// `executeArb` without an external provider or Anvil.
    ///
    /// `deployer` must be funded (ETH balance) in the provided `state`
    /// before calling this method. The method funds the deployer
    /// internally with 100 ETH as a convenience.
    ///
    /// Returns `SimulationResult` where `profit_wei` is the post-call
    /// balance of `profit_recipient` minus the pre-call balance (in
    /// `profit_token` ERC20, read via `balance_slot`). On any failure
    /// (CREATE revert, CALL revert), returns `success: false`.
    #[allow(clippy::too_many_arguments)]
    pub fn deploy_and_simulate_with_erc20_profit(
        &self,
        mut state: RpcForkedState,
        deployer: Address,
        init_bytecode: &[u8],
        constructor_args: &[u8],
        calldata: Vec<u8>,
        profit_token: Address,
        profit_recipient: Address,
        balance_slot: U256,
    ) -> SimulationResult {
        use revm::context::result::Output;
        use revm::database::DatabaseRef;

        // Fund the deployer so CREATE and CALL can proceed without
        // balance-check failures even when `disable_balance_check` is set.
        let hundred_eth = U256::from(100u64) * U256::from(10u64).pow(U256::from(18u64));
        state.insert_account_balance(deployer, hundred_eth);

        // Concatenate init bytecode + constructor args.
        let mut deploy_data = Vec::with_capacity(init_bytecode.len() + constructor_args.len());
        deploy_data.extend_from_slice(init_bytecode);
        deploy_data.extend_from_slice(constructor_args);

        // Destructure state for revm consumption.
        let RpcForkedState {
            db,
            block_number,
            block_timestamp,
            base_fee,
            chain_id,
        } = state;

        let block = BlockEnv {
            number: U256::from(block_number),
            timestamp: U256::from(block_timestamp),
            basefee: base_fee,
            ..Default::default()
        };

        // === Transact 1: CREATE ===
        let create_tx = TxEnv::builder()
            .caller(deployer)
            .kind(revm::primitives::TxKind::Create)
            .data(revm::primitives::Bytes::copy_from_slice(&deploy_data))
            .value(U256::ZERO)
            .gas_limit(8_000_000)
            .gas_price(base_fee as u128)
            .nonce(0)
            .chain_id(Some(chain_id))
            .build_fill();

        let ctx = Context::<BlockEnv, TxEnv, _, RpcDB, revm::context::Journal<RpcDB>, ()>::new(
            db, SpecId::CANCUN,
        )
        .with_block(block.clone())
        .modify_cfg_chained(|cfg| {
            cfg.chain_id = chain_id;
            cfg.disable_nonce_check = true;
            cfg.disable_balance_check = true;
            cfg.disable_base_fee = true;
        });

        let mut evm = ctx.build_mainnet();

        let create_result = match evm.transact(create_tx) {
            Ok(r) => r,
            Err(e) => {
                error!(error = %e, "CREATE transact error");
                return SimulationResult {
                    success: false,
                    profit_wei: U256::ZERO,
                    gas_used: 0,
                    revert_reason: Some(format!("CREATE EVM error: {e}")),
                };
            }
        };

        let deployed_addr = match create_result.result {
            ExecutionResult::Success { output: Output::Create(_, Some(addr)), .. } => addr,
            ExecutionResult::Success { output: Output::Create(_, None), .. } => {
                return SimulationResult {
                    success: false,
                    profit_wei: U256::ZERO,
                    gas_used: 0,
                    revert_reason: Some("CREATE succeeded but no address returned".into()),
                };
            }
            ExecutionResult::Revert { gas_used, output } => {
                let reason = format!("0x{}", alloy::hex::encode(&output));
                return SimulationResult {
                    success: false,
                    profit_wei: U256::ZERO,
                    gas_used,
                    revert_reason: Some(format!("CREATE reverted: {reason}")),
                };
            }
            ExecutionResult::Halt { reason, gas_used } => {
                return SimulationResult {
                    success: false,
                    profit_wei: U256::ZERO,
                    gas_used,
                    revert_reason: Some(format!("CREATE halted: {reason:?}")),
                };
            }
            _ => {
                return SimulationResult {
                    success: false,
                    profit_wei: U256::ZERO,
                    gas_used: 0,
                    revert_reason: Some("CREATE returned unexpected output variant".into()),
                };
            }
        };

        debug!(%deployed_addr, "CREATE succeeded, proceeding to CALL");

        // Commit CREATE state diffs into the DB so the CALL sees them.
        let mut db = evm.ctx.journaled_state.database;
        for (addr, account) in create_result.state.iter() {
            if account.is_selfdestructed() {
                continue;
            }
            let info = &account.info;
            db.insert_account_info(
                *addr,
                AccountInfo {
                    balance: info.balance,
                    nonce: info.nonce,
                    code_hash: info.code_hash,
                    code: info.code.clone(),
                    ..Default::default()
                },
            );
            for (slot, slot_val) in account.storage.iter() {
                let _ = db.insert_account_storage(*addr, *slot, slot_val.present_value);
            }
        }

        // === Pre-call balance read ===
        let mut key_input = [0u8; 64];
        key_input[12..32].copy_from_slice(profit_recipient.as_slice());
        key_input[32..64].copy_from_slice(&balance_slot.to_be_bytes::<32>());
        let storage_key = U256::from_be_slice(
            alloy::primitives::keccak256(key_input).as_slice(),
        );
        let pre_balance = db
            .storage_ref(profit_token, storage_key)
            .unwrap_or_default();

        // === Transact 2: CALL the deployed contract ===
        let call_tx = TxEnv::builder()
            .caller(deployer)
            .kind(revm::primitives::TxKind::Call(deployed_addr))
            .data(revm::primitives::Bytes::copy_from_slice(&calldata))
            .value(U256::ZERO)
            .gas_limit(self.config.gas_limit)
            .gas_price(base_fee as u128)
            .nonce(1)
            .chain_id(Some(chain_id))
            .build_fill();

        let ctx2 = Context::<BlockEnv, TxEnv, _, RpcDB, revm::context::Journal<RpcDB>, ()>::new(
            db, SpecId::CANCUN,
        )
        .with_block(block)
        .modify_cfg_chained(|cfg| {
            cfg.chain_id = chain_id;
            cfg.disable_nonce_check = true;
            cfg.disable_balance_check = true;
            cfg.disable_base_fee = true;
        });

        let mut evm2 = ctx2.build_mainnet();

        match evm2.transact(call_tx) {
            Ok(result_and_state) => match result_and_state.result {
                ExecutionResult::Success { gas_used, .. } => {
                    let post_balance = result_and_state
                        .state
                        .get(&profit_token)
                        .and_then(|acc| acc.storage.get(&storage_key))
                        .map(|slot| slot.present_value)
                        .unwrap_or(pre_balance);

                    let profit = post_balance.saturating_sub(pre_balance);
                    debug!(gas_used, %profit, "deploy+call simulation succeeded");
                    SimulationResult {
                        success: true,
                        profit_wei: profit,
                        gas_used,
                        revert_reason: None,
                    }
                }
                ExecutionResult::Revert { gas_used, output } => {
                    let reason = format!("0x{}", alloy::hex::encode(&output));
                    debug!(gas_used, reason = %reason, "CALL reverted");
                    SimulationResult {
                        success: false,
                        profit_wei: U256::ZERO,
                        gas_used,
                        revert_reason: Some(reason),
                    }
                }
                ExecutionResult::Halt { reason, gas_used } => {
                    let reason_str = format!("{reason:?}");
                    debug!(gas_used, reason = %reason_str, "CALL halted");
                    SimulationResult {
                        success: false,
                        profit_wei: U256::ZERO,
                        gas_used,
                        revert_reason: Some(reason_str),
                    }
                }
            },
            Err(e) => {
                error!(error = %e, "CALL transact error");
                SimulationResult {
                    success: false,
                    profit_wei: U256::ZERO,
                    gas_used: 0,
                    revert_reason: Some(format!("CALL EVM error: {e}")),
                }
            }
        }
    }

    /// Simulate a transaction against RPC-backed state and measure the ERC20
    /// balance delta of `profit_recipient` for `profit_token` as profit.
    ///
    /// Implementation detail: we cannot observe storage writes by re-reading
    /// through `RpcDB` after `transact` consumes the context, so we inspect
    /// the returned `result_and_state.state` map directly. The ERC20 balance
    /// slot for most tokens (WETH / USDC / DAI / USDT) is `mapping(address
    /// => uint256) _balances` at slot 3 (WETH), 9 (USDC), or 2 (USDT / DAI).
    /// The caller passes `balance_slot` to select the right slot for the
    /// token of interest.
    ///
    /// Pre-sim balance is read via `db.storage(...)` which either serves
    /// from cache or triggers an AlloyDB RPC fetch; post-sim balance is read
    /// from `result_and_state.state[token].storage[slot]` — and falls back
    /// to pre-sim balance if the sim didn't touch that slot (e.g. revert).
    pub fn simulate_rpc_with_erc20_profit(
        &self,
        state: RpcForkedState,
        to: Address,
        calldata: Vec<u8>,
        profit_token: Address,
        profit_recipient: Address,
        balance_slot: U256,
    ) -> SimulationResult {
        use revm::database::DatabaseRef;

        // Compute the balanceOf(recipient) storage key:
        //   slot = keccak256(pad32(recipient) ++ pad32(balance_slot))
        let mut key_input = [0u8; 64];
        key_input[12..32].copy_from_slice(profit_recipient.as_slice());
        key_input[32..64].copy_from_slice(&balance_slot.to_be_bytes::<32>());
        let storage_key = U256::from_be_slice(
            alloy::primitives::keccak256(key_input).as_slice(),
        );

        // Pre-sim balance via DatabaseRef::storage_ref (fetches from RPC on
        // first access, then serves from cache). `state.db` implements
        // DatabaseRef from revm. We destructure state so that we can use db
        // after transact consumes the context.
        let RpcForkedState {
            db,
            block_number,
            block_timestamp,
            base_fee,
            chain_id,
        } = state;

        let pre_balance = db
            .storage_ref(profit_token, storage_key)
            .unwrap_or_default();

        let block = BlockEnv {
            number: U256::from(block_number),
            timestamp: U256::from(block_timestamp),
            basefee: base_fee,
            ..Default::default()
        };

        let tx = TxEnv::builder()
            .caller(self.config.caller)
            .kind(revm::primitives::TxKind::Call(to))
            .data(revm::primitives::Bytes::copy_from_slice(&calldata))
            .value(self.config.value)
            .gas_limit(self.config.gas_limit)
            .gas_price(base_fee as u128)
            .nonce(0)
            .chain_id(Some(chain_id))
            .build_fill();

        let ctx = Context::<BlockEnv, TxEnv, _, RpcDB, revm::context::Journal<RpcDB>, ()>::new(
            db, SpecId::CANCUN,
        )
        .with_block(block)
        .modify_cfg_chained(|cfg| {
            cfg.chain_id = chain_id;
            cfg.disable_nonce_check = true;
            // Replay sims run from an impersonated SIM_OWNER that may not
            // have ETH on the *pinned* RPC block even when `anvil_setBalance`
            // has bumped it on Anvil's current head; revm's balance check
            // would then fail pre-flight. Disable it — we're measuring
            // executability, not caller solvency.
            cfg.disable_balance_check = true;
            // Likewise skip base-fee floor; our nominal gas_price doesn't
            // need to match the pinned block's EIP-1559 base fee.
            cfg.disable_base_fee = true;
        });

        let mut evm = ctx.build_mainnet();

        match evm.transact(tx) {
            Ok(result_and_state) => match result_and_state.result {
                ExecutionResult::Success { gas_used, .. } => {
                    // Extract post-sim balance from the state diff. If the
                    // sim didn't touch the token's balance slot for our
                    // recipient, the diff will lack an entry and we fall
                    // back to pre-sim balance → profit = 0.
                    let post_balance = result_and_state
                        .state
                        .get(&profit_token)
                        .and_then(|acc| acc.storage.get(&storage_key))
                        .map(|slot| slot.present_value)
                        .unwrap_or(pre_balance);

                    let profit = post_balance.saturating_sub(pre_balance);
                    debug!(gas_used, %profit, "RPC simulation with ERC20 profit succeeded");
                    SimulationResult {
                        success: true,
                        profit_wei: profit,
                        gas_used,
                        revert_reason: None,
                    }
                }
                ExecutionResult::Revert { gas_used, output } => {
                    let reason = format!("0x{}", alloy::hex::encode(&output));
                    debug!(gas_used, reason = %reason, "RPC simulation reverted");
                    SimulationResult {
                        success: false,
                        profit_wei: U256::ZERO,
                        gas_used,
                        revert_reason: Some(reason),
                    }
                }
                ExecutionResult::Halt { reason, gas_used } => {
                    let reason_str = format!("{:?}", reason);
                    debug!(gas_used, reason = %reason_str, "RPC simulation halted");
                    SimulationResult {
                        success: false,
                        profit_wei: U256::ZERO,
                        gas_used,
                        revert_reason: Some(reason_str),
                    }
                }
            },
            Err(e) => {
                error!(error = %e, "RPC EVM transact error");
                SimulationResult {
                    success: false,
                    profit_wei: U256::ZERO,
                    gas_used: 0,
                    revert_reason: Some(format!("EVM error: {}", e)),
                }
            }
        }
    }
}

