//! Post-state replayer — revm fork-replay of a pending victim tx, then
//! read the affected pool's storage post-execution to recover its new
//! analytical state.
//!
//! Fallback path for cases the closed-form predictor in `aether-pools`
//! can't handle: V3 swaps that cross at least one tick boundary, Curve
//! StableSwap iterations that don't converge, Balancer pools with
//! unequal weights. In all three cases the analytical predictor returns
//! a low-confidence flag — replaying the victim against a real forked
//! EVM and reading the pool's new storage gives an exact answer.
//!
//! The Uniswap V3 reader pulls `slot0()` + `liquidity()` after the
//! victim commits. The Curve reader pulls `balances(uint256 i)` for the
//! two coin indices involved in the swap. The Balancer V2 reader resolves
//! the pool's `bytes32 poolId` via `getPoolId()` on the pool contract
//! then calls `IVault.getPoolTokens(poolId)` on the canonical mainnet
//! Vault, picking out the two balances aligned with `(token_in, token_out)`.
//!
//! Like `mempool_backrun`, this module is a synchronous pure function
//! so callers can run it on `spawn_blocking` workers without leaking
//! async dependencies.

use alloy::primitives::{address, Address, FixedBytes, U256};
use alloy::sol;
use alloy::sol_types::SolCall;
use aether_pools::balancer::BalancerPostState;
use aether_pools::curve::CurvePostState;
use aether_pools::uniswap_v3::V3PostState;
use revm::context::result::ExecutionResult;
use revm::context::{BlockEnv, TxEnv};
use revm::database::CacheDB;
use revm::database_interface::{Database, DatabaseRef};
use revm::handler::{ExecuteCommitEvm, ExecuteEvm, MainBuilder};
use revm::primitives::hardfork::SpecId;
use revm::Context;
use tracing::debug;

use crate::fork::{ForkedState, RpcForkedState};
use crate::mempool_backrun::VictimTx;

/// Canonical Balancer V2 Vault on Ethereum mainnet. Every weighted /
/// stable / linear pool routes its balance bookkeeping through this
/// singleton; the replay reader calls `getPoolTokens(poolId)` on it
/// to recover post-swap balances.
pub const BALANCER_V2_VAULT: Address = address!("BA12222222228d8Ba445958a75a0704d566BF2C8");

sol! {
    interface IUniswapV3PoolReader {
        function slot0() external view returns (
            uint160 sqrtPriceX96,
            int24 tick,
            uint16 observationIndex,
            uint16 observationCardinality,
            uint16 observationCardinalityNext,
            uint8 feeProtocol,
            bool unlocked
        );
        function liquidity() external view returns (uint128);
    }

    interface ICurvePoolReader {
        function balances(uint256 i) external view returns (uint256);
    }

    interface IBalancerPoolReader {
        function getPoolId() external view returns (bytes32);
    }

    interface IBalancerVaultReader {
        function getPoolTokens(bytes32 poolId)
            external
            view
            returns (address[] memory tokens, uint256[] memory balances, uint256 lastChangeBlock);
    }
}

/// Why a post-state replay attempt did not produce a usable result.
/// Maps 1:1 onto the `aether_mempool_post_state_replay_total{outcome}`
/// label set in `crates/grpc-server/src/metrics.rs`.
#[derive(Debug, Clone, PartialEq, Eq)]
pub enum ReplayError {
    /// Victim tx executed but reverted on-chain. The replay path returns
    /// no useful post-state — analytical predictor was already going to
    /// skip this candidate anyway.
    VictimReverted,
    /// Victim tx halted (out-of-gas / stack overflow / etc.). Same
    /// downstream impact as `VictimReverted`.
    VictimHalted,
    /// View call against the pool's reader interface failed after the
    /// victim was committed (e.g. pool address has no bytecode, or
    /// returned an unexpected revert). String is the function name.
    ReadCallFailed(&'static str),
    /// ABI decode of a successful view call's output failed. Indicates
    /// either a corrupt pool or an unexpected ABI shape. String is the
    /// function name.
    DecodeFailed(&'static str),
    /// EVM dispatch itself errored (e.g. AlloyDB RPC failure). The
    /// candidate is dropped without further consequence.
    SimError,
    /// Replayer was invoked for a protocol family it does not yet
    /// implement (Curve / Balancer). String is the protocol label.
    UnimplementedProtocol(&'static str),
}

impl ReplayError {
    pub fn as_str(&self) -> &'static str {
        match self {
            Self::VictimReverted => "victim_reverted",
            Self::VictimHalted => "victim_halted",
            Self::ReadCallFailed(_) => "read_call_failed",
            Self::DecodeFailed(_) => "decode_failed",
            Self::SimError => "sim_error",
            Self::UnimplementedProtocol(_) => "unimplemented_protocol",
        }
    }
}

/// Block-context parameters needed to build the revm BlockEnv for the
/// victim's intended slot. The caller resolves these once per pending tx
/// (block number from the snapshot manager + timestamp / basefee from
/// the latest block header).
#[derive(Debug, Clone)]
pub struct ReplayParams {
    pub block_number: u64,
    pub block_timestamp: u64,
    pub base_fee: u64,
    pub chain_id: u64,
}

/// Replay the victim tx against an RPC-backed fork and read the V3
/// pool's `slot0() + liquidity()` post-execution. Production entry point.
pub fn replay_v3_post_state_rpc(
    state: RpcForkedState,
    victim: &VictimTx,
    pool: Address,
    params: &ReplayParams,
) -> Result<V3PostState, ReplayError> {
    let RpcForkedState { db, .. } = state;
    replay_v3_inner(db, victim, pool, params)
}

/// Replay the victim tx against a synthetic `ForkedState` and read the
/// V3 pool's post-state. Used by unit tests that pre-populate storage
/// without standing up a full RPC fork.
pub fn replay_v3_post_state_cache(
    state: ForkedState,
    victim: &VictimTx,
    pool: Address,
    params: &ReplayParams,
) -> Result<V3PostState, ReplayError> {
    replay_v3_inner(state.db, victim, pool, params)
}

/// Replay the victim tx against an RPC-backed fork and read a 2-coin
/// Curve pool's `balances(i)` and `balances(j)` post-execution. The
/// caller supplies the coin indices because Curve V1 pools store
/// `tokens` and `balances` as parallel arrays and the on-chain
/// `balances(uint256)` view is keyed on that index, not on a token
/// address — the `CurvePool` cached state in `aether-pools` already
/// knows the index for both ends of the swap.
///
/// `amount_out` is the difference between the pre-swap `balances(j)`
/// (read off the cached `CurvePool` by the caller) and the post-swap
/// value returned here. The reader does not re-derive it because the
/// caller has the pre-state already and feeding the pre-balance through
/// here would only duplicate that information.
pub fn replay_curve_post_state_rpc(
    state: RpcForkedState,
    victim: &VictimTx,
    pool: Address,
    coin_idx_in: u8,
    coin_idx_out: u8,
    params: &ReplayParams,
) -> Result<CurvePostState, ReplayError> {
    let RpcForkedState { db, .. } = state;
    replay_curve_inner(db, victim, pool, coin_idx_in, coin_idx_out, params)
}

/// Cache-backed sibling of [`replay_curve_post_state_rpc`] for tests that
/// pre-populate a synthetic `ForkedState` instead of standing up a real
/// RPC fork.
pub fn replay_curve_post_state_cache(
    state: ForkedState,
    victim: &VictimTx,
    pool: Address,
    coin_idx_in: u8,
    coin_idx_out: u8,
    params: &ReplayParams,
) -> Result<CurvePostState, ReplayError> {
    replay_curve_inner(state.db, victim, pool, coin_idx_in, coin_idx_out, params)
}

/// Replay the victim tx against an RPC-backed fork and read a Balancer
/// V2 pool's post-swap balances via the canonical Vault. The pool
/// contract is queried for its `bytes32 poolId`, then
/// `IVault.getPoolTokens(poolId)` is called on the Vault — both reads
/// run against the same post-commit EVM context so they always reflect
/// the victim's effect.
///
/// `token0` / `token1` are the pool's canonical token ordering (as
/// stored on the cached `BalancerPool`). The returned `BalancerPostState`
/// keeps `new_balance0` aligned with `token0` and `new_balance1` with
/// `token1`, matching the analytical-path convention so the consumer's
/// `unified_to_post_reserves` helper can re-derive swap direction
/// uniformly across analytical and replay branches.
pub fn replay_balancer_post_state_rpc(
    state: RpcForkedState,
    victim: &VictimTx,
    pool: Address,
    token0: Address,
    token1: Address,
    params: &ReplayParams,
) -> Result<BalancerPostState, ReplayError> {
    let RpcForkedState { db, .. } = state;
    replay_balancer_inner(db, victim, pool, BALANCER_V2_VAULT, token0, token1, params)
}

/// Cache-backed sibling of [`replay_balancer_post_state_rpc`]. Tests
/// supply both the pool address and the Vault address explicitly so a
/// synthetic mock can stand in for the canonical mainnet Vault.
pub fn replay_balancer_post_state_cache(
    state: ForkedState,
    victim: &VictimTx,
    pool: Address,
    vault: Address,
    token0: Address,
    token1: Address,
    params: &ReplayParams,
) -> Result<BalancerPostState, ReplayError> {
    replay_balancer_inner(state.db, victim, pool, vault, token0, token1, params)
}

fn replay_v3_inner<DB>(
    db: CacheDB<DB>,
    victim: &VictimTx,
    pool: Address,
    params: &ReplayParams,
) -> Result<V3PostState, ReplayError>
where
    DB: DatabaseRef,
    CacheDB<DB>: Database<Error = <DB as DatabaseRef>::Error>,
    <DB as DatabaseRef>::Error: std::fmt::Debug,
{
    let block = BlockEnv {
        number: U256::from(params.block_number),
        timestamp: U256::from(params.block_timestamp),
        basefee: params.base_fee,
        ..Default::default()
    };

    let ctx = Context::<BlockEnv, TxEnv, _, CacheDB<DB>, revm::context::Journal<CacheDB<DB>>, ()>::new(
        db, SpecId::CANCUN,
    )
    .with_block(block)
    .modify_cfg_chained(|cfg| {
        cfg.chain_id = params.chain_id;
        cfg.disable_nonce_check = true;
        cfg.disable_balance_check = true;
        cfg.disable_base_fee = true;
    });

    let mut evm = ctx.build_mainnet();

    let victim_env = TxEnv::builder()
        .caller(victim.from)
        .kind(revm::primitives::TxKind::Call(victim.to))
        .data(revm::primitives::Bytes::copy_from_slice(&victim.data))
        .value(victim.value)
        .gas_limit(victim.gas_limit)
        .gas_price(victim.gas_price)
        .nonce(0)
        .chain_id(Some(params.chain_id))
        .build_fill();

    match evm.transact_commit(victim_env) {
        Ok(ExecutionResult::Success { .. }) => {}
        Ok(ExecutionResult::Revert { .. }) => return Err(ReplayError::VictimReverted),
        Ok(ExecutionResult::Halt { .. }) => return Err(ReplayError::VictimHalted),
        Err(e) => {
            debug!(error = ?e, "post-state replay: victim sim error");
            return Err(ReplayError::SimError);
        }
    }

    // Read slot0() against post-victim state.
    let slot0_data = IUniswapV3PoolReader::slot0Call {}.abi_encode();
    let slot0_env = build_view_env(pool, slot0_data, params.chain_id);
    let slot0_output = match evm.transact(slot0_env) {
        Ok(rs) => match rs.result {
            ExecutionResult::Success { output, .. } => output.into_data(),
            _ => return Err(ReplayError::ReadCallFailed("slot0")),
        },
        Err(_) => return Err(ReplayError::ReadCallFailed("slot0")),
    };
    let decoded_slot0 = IUniswapV3PoolReader::slot0Call::abi_decode_returns(&slot0_output)
        .map_err(|_| ReplayError::DecodeFailed("slot0"))?;

    // Read liquidity() against the same post-victim state.
    let liq_data = IUniswapV3PoolReader::liquidityCall {}.abi_encode();
    let liq_env = build_view_env(pool, liq_data, params.chain_id);
    let liq_output = match evm.transact(liq_env) {
        Ok(rs) => match rs.result {
            ExecutionResult::Success { output, .. } => output.into_data(),
            _ => return Err(ReplayError::ReadCallFailed("liquidity")),
        },
        Err(_) => return Err(ReplayError::ReadCallFailed("liquidity")),
    };
    let decoded_liq = IUniswapV3PoolReader::liquidityCall::abi_decode_returns(&liq_output)
        .map_err(|_| ReplayError::DecodeFailed("liquidity"))?;

    // `amount_out` is intentionally left as `U256::ZERO` — the graph-edge
    // update in `unified_to_post_reserves` derives virtual constant-product
    // reserves from `new_sqrt_price_x96` AND `new_liquidity` (both read here)
    // and never reads `amount_out` for V3. Setting `single_tick = true`
    // because the post-state was read directly from post-execution storage
    // and the multi-tick precision concern that motivates the flag does not
    // apply to revm-derived values.
    Ok(V3PostState {
        new_sqrt_price_x96: U256::from(decoded_slot0.sqrtPriceX96),
        new_liquidity: decoded_liq,
        amount_out: U256::ZERO,
        single_tick: true,
    })
}

fn build_view_env(pool: Address, data: Vec<u8>, chain_id: u64) -> TxEnv {
    TxEnv::builder()
        .caller(Address::ZERO)
        .kind(revm::primitives::TxKind::Call(pool))
        .data(revm::primitives::Bytes::from(data))
        .value(U256::ZERO)
        .gas_limit(1_000_000)
        .gas_price(0)
        .nonce(0)
        .chain_id(Some(chain_id))
        .build_fill()
}

fn replay_curve_inner<DB>(
    db: CacheDB<DB>,
    victim: &VictimTx,
    pool: Address,
    coin_idx_in: u8,
    coin_idx_out: u8,
    params: &ReplayParams,
) -> Result<CurvePostState, ReplayError>
where
    DB: DatabaseRef,
    CacheDB<DB>: Database<Error = <DB as DatabaseRef>::Error>,
    <DB as DatabaseRef>::Error: std::fmt::Debug,
{
    let block = BlockEnv {
        number: U256::from(params.block_number),
        timestamp: U256::from(params.block_timestamp),
        basefee: params.base_fee,
        ..Default::default()
    };
    let ctx = Context::<BlockEnv, TxEnv, _, CacheDB<DB>, revm::context::Journal<CacheDB<DB>>, ()>::new(
        db, SpecId::CANCUN,
    )
    .with_block(block)
    .modify_cfg_chained(|cfg| {
        cfg.chain_id = params.chain_id;
        cfg.disable_nonce_check = true;
        cfg.disable_balance_check = true;
        cfg.disable_base_fee = true;
    });
    let mut evm = ctx.build_mainnet();

    let victim_env = TxEnv::builder()
        .caller(victim.from)
        .kind(revm::primitives::TxKind::Call(victim.to))
        .data(revm::primitives::Bytes::copy_from_slice(&victim.data))
        .value(victim.value)
        .gas_limit(victim.gas_limit)
        .gas_price(victim.gas_price)
        .nonce(0)
        .chain_id(Some(params.chain_id))
        .build_fill();

    match evm.transact_commit(victim_env) {
        Ok(ExecutionResult::Success { .. }) => {}
        Ok(ExecutionResult::Revert { .. }) => return Err(ReplayError::VictimReverted),
        Ok(ExecutionResult::Halt { .. }) => return Err(ReplayError::VictimHalted),
        Err(e) => {
            debug!(error = ?e, "post-state replay: victim sim error (curve)");
            return Err(ReplayError::SimError);
        }
    }

    // Read `balances(i)` against post-victim state for both coin indices.
    let in_data = ICurvePoolReader::balancesCall { i: U256::from(coin_idx_in) }.abi_encode();
    let in_env = build_view_env(pool, in_data, params.chain_id);
    let in_output = match evm.transact(in_env) {
        Ok(rs) => match rs.result {
            ExecutionResult::Success { output, .. } => output.into_data(),
            _ => return Err(ReplayError::ReadCallFailed("balances")),
        },
        Err(_) => return Err(ReplayError::ReadCallFailed("balances")),
    };
    let new_balance_in = ICurvePoolReader::balancesCall::abi_decode_returns(&in_output)
        .map_err(|_| ReplayError::DecodeFailed("balances"))?;

    let out_data = ICurvePoolReader::balancesCall { i: U256::from(coin_idx_out) }.abi_encode();
    let out_env = build_view_env(pool, out_data, params.chain_id);
    let out_output = match evm.transact(out_env) {
        Ok(rs) => match rs.result {
            ExecutionResult::Success { output, .. } => output.into_data(),
            _ => return Err(ReplayError::ReadCallFailed("balances")),
        },
        Err(_) => return Err(ReplayError::ReadCallFailed("balances")),
    };
    let new_balance_out = ICurvePoolReader::balancesCall::abi_decode_returns(&out_output)
        .map_err(|_| ReplayError::DecodeFailed("balances"))?;

    // `i`/`j` here are usize-widened from the caller-supplied coin indices
    // (Curve V1 pools index coins as a uint256 on-chain but the index
    // always fits in a u8 in practice — 2- and 3-coin pools dominate).
    // `amount_out` is intentionally `U256::ZERO`: `unified_to_post_reserves`
    // in the mempool pipeline only consumes `new_balance_in`/`new_balance_out`
    // for Curve and never reads `amount_out`. Setting `analytical = false`
    // preserves the existing label space — the replay path is the
    // non-analytical branch by definition.
    Ok(CurvePostState {
        i: coin_idx_in as usize,
        j: coin_idx_out as usize,
        new_balance_in,
        new_balance_out,
        amount_out: U256::ZERO,
        analytical: false,
    })
}

#[allow(clippy::too_many_arguments)]
fn replay_balancer_inner<DB>(
    db: CacheDB<DB>,
    victim: &VictimTx,
    pool: Address,
    vault: Address,
    token0: Address,
    token1: Address,
    params: &ReplayParams,
) -> Result<BalancerPostState, ReplayError>
where
    DB: DatabaseRef,
    CacheDB<DB>: Database<Error = <DB as DatabaseRef>::Error>,
    <DB as DatabaseRef>::Error: std::fmt::Debug,
{
    let block = BlockEnv {
        number: U256::from(params.block_number),
        timestamp: U256::from(params.block_timestamp),
        basefee: params.base_fee,
        ..Default::default()
    };
    let ctx = Context::<BlockEnv, TxEnv, _, CacheDB<DB>, revm::context::Journal<CacheDB<DB>>, ()>::new(
        db, SpecId::CANCUN,
    )
    .with_block(block)
    .modify_cfg_chained(|cfg| {
        cfg.chain_id = params.chain_id;
        cfg.disable_nonce_check = true;
        cfg.disable_balance_check = true;
        cfg.disable_base_fee = true;
    });
    let mut evm = ctx.build_mainnet();

    let victim_env = TxEnv::builder()
        .caller(victim.from)
        .kind(revm::primitives::TxKind::Call(victim.to))
        .data(revm::primitives::Bytes::copy_from_slice(&victim.data))
        .value(victim.value)
        .gas_limit(victim.gas_limit)
        .gas_price(victim.gas_price)
        .nonce(0)
        .chain_id(Some(params.chain_id))
        .build_fill();

    match evm.transact_commit(victim_env) {
        Ok(ExecutionResult::Success { .. }) => {}
        Ok(ExecutionResult::Revert { .. }) => return Err(ReplayError::VictimReverted),
        Ok(ExecutionResult::Halt { .. }) => return Err(ReplayError::VictimHalted),
        Err(e) => {
            debug!(error = ?e, "post-state replay: victim sim error (balancer)");
            return Err(ReplayError::SimError);
        }
    }

    // Step 1: resolve poolId by calling `getPoolId()` on the pool contract.
    let pool_id_data = IBalancerPoolReader::getPoolIdCall {}.abi_encode();
    let pool_id_env = build_view_env(pool, pool_id_data, params.chain_id);
    let pool_id_output = match evm.transact(pool_id_env) {
        Ok(rs) => match rs.result {
            ExecutionResult::Success { output, .. } => output.into_data(),
            _ => return Err(ReplayError::ReadCallFailed("getPoolId")),
        },
        Err(_) => return Err(ReplayError::ReadCallFailed("getPoolId")),
    };
    let pool_id: FixedBytes<32> = IBalancerPoolReader::getPoolIdCall::abi_decode_returns(&pool_id_output)
        .map_err(|_| ReplayError::DecodeFailed("getPoolId"))?;

    // Step 2: call `getPoolTokens(poolId)` on the Vault.
    let tokens_data = IBalancerVaultReader::getPoolTokensCall { poolId: pool_id }.abi_encode();
    let tokens_env = build_view_env(vault, tokens_data, params.chain_id);
    let tokens_output = match evm.transact(tokens_env) {
        Ok(rs) => match rs.result {
            ExecutionResult::Success { output, .. } => output.into_data(),
            _ => return Err(ReplayError::ReadCallFailed("getPoolTokens")),
        },
        Err(_) => return Err(ReplayError::ReadCallFailed("getPoolTokens")),
    };
    let decoded = IBalancerVaultReader::getPoolTokensCall::abi_decode_returns(&tokens_output)
        .map_err(|_| ReplayError::DecodeFailed("getPoolTokens"))?;

    // Walk the Vault's `(tokens, balances)` parallel arrays once and pick
    // out the entries matching the pool's canonical `(token0, token1)`
    // ordering. Matching by address (not by index) is robust to Balancer's
    // pool-registration ordering, which is not guaranteed to mirror the
    // engine's cached `(token0, token1)` convention.
    let mut bal0: Option<U256> = None;
    let mut bal1: Option<U256> = None;
    for (tok, bal) in decoded.tokens.iter().zip(decoded.balances.iter()) {
        if *tok == token0 {
            bal0 = Some(*bal);
        } else if *tok == token1 {
            bal1 = Some(*bal);
        }
    }
    let (Some(b0), Some(b1)) = (bal0, bal1) else {
        return Err(ReplayError::DecodeFailed("getPoolTokens"));
    };

    // `amount_out = U256::ZERO` because the consumer
    // (`unified_to_post_reserves`) derives output amounts from the
    // graph-edge update, not from this field. The analytical flag stays
    // `false` since revm-derived state is the non-analytical branch by
    // construction.
    Ok(BalancerPostState {
        new_balance0: b0,
        new_balance1: b1,
        amount_out: U256::ZERO,
        analytical: false,
    })
}

#[cfg(test)]
mod tests {
    use super::*;
    use alloy::primitives::address;

    fn default_params() -> ReplayParams {
        ReplayParams {
            block_number: 18_000_000,
            block_timestamp: 1_700_000_000,
            base_fee: 1_000_000_000,
            chain_id: 1,
        }
    }

    fn default_victim() -> VictimTx {
        VictimTx {
            from: address!("2222222222222222222222222222222222222222"),
            to: address!("3333333333333333333333333333333333333333"),
            value: U256::ZERO,
            data: vec![],
            gas_price: 1_000_000_000,
            gas_limit: 500_000,
        }
    }

    #[test]
    fn reject_when_pool_address_has_no_bytecode() {
        // Empty target accepts the victim call (revm treats no-code call
        // as a value transfer success). The slot0() read against a
        // codeless pool address returns empty output; ABI decode then
        // fails because the slot0() return tuple needs ~224 bytes. The
        // decode-failed branch is the right rejection surface — it tells
        // the caller "this isn't a V3 pool" rather than implying the EVM
        // dispatch itself broke.
        let state = ForkedState::new_empty(18_000_000, 1_700_000_000, 1_000_000_000);
        let pool = address!("88e6A0c2dDD26FEEb64F039a2c41296FcB3f5640");
        let result = replay_v3_post_state_cache(state, &default_victim(), pool, &default_params());
        assert!(
            matches!(result, Err(ReplayError::DecodeFailed("slot0"))),
            "expected DecodeFailed(slot0), got {result:?}"
        );
    }

    #[test]
    fn reject_when_pool_address_is_an_eoa() {
        // Same shape as the no-bytecode case, but with the victim target
        // funded so its execution path stays clean. The decode failure
        // again surfaces from the codeless pool read.
        let mut state = ForkedState::new_empty(18_000_000, 1_700_000_000, 1_000_000_000);
        state.insert_account_balance(default_victim().to, U256::from(10u128.pow(18)));
        let pool = address!("88e6A0c2dDD26FEEb64F039a2c41296FcB3f5640");
        let result = replay_v3_post_state_cache(state, &default_victim(), pool, &default_params());
        assert!(
            matches!(result, Err(ReplayError::DecodeFailed("slot0"))),
            "expected DecodeFailed(slot0), got {result:?}"
        );
    }

    #[test]
    fn curve_replay_decode_failed_when_pool_has_no_bytecode() {
        // Codeless pool address — the `balances(i)` view returns empty
        // output and ABI decode then fails, surfacing as
        // `DecodeFailed("balances")`. This is the expected rejection
        // path for a Curve replay against an address that isn't a real
        // StableSwap pool.
        let state = ForkedState::new_empty(18_000_000, 1_700_000_000, 1_000_000_000);
        let pool = address!("bEbc44782C7dB0a1A60Cb6fe97d0b483032FF1C7");
        let result = replay_curve_post_state_cache(
            state,
            &default_victim(),
            pool,
            0,
            1,
            &default_params(),
        );
        assert!(
            matches!(result, Err(ReplayError::DecodeFailed("balances"))),
            "expected DecodeFailed(balances), got {result:?}"
        );
    }

    #[test]
    fn balancer_replay_decode_failed_when_pool_has_no_bytecode() {
        // Codeless pool address — the `getPoolId()` read fails to
        // ABI-decode. Surfaces as `DecodeFailed("getPoolId")`, which is
        // the right reason for a non-Balancer address routed into the
        // Balancer replay path.
        let state = ForkedState::new_empty(18_000_000, 1_700_000_000, 1_000_000_000);
        let pool = address!("5c6Ee304399DBdB9C8Ef030aB642B10820DB8F56");
        let vault = BALANCER_V2_VAULT;
        let t0 = address!("C02aaA39b223FE8D0A0e5C4F27eAD9083C756Cc2");
        let t1 = address!("ba100000625a3754423978a60c9317c58a424e3D");
        let result = replay_balancer_post_state_cache(
            state,
            &default_victim(),
            pool,
            vault,
            t0,
            t1,
            &default_params(),
        );
        assert!(
            matches!(result, Err(ReplayError::DecodeFailed("getPoolId"))),
            "expected DecodeFailed(getPoolId), got {result:?}"
        );
    }

    /// Build runtime bytecode that returns the same 32-byte word for
    /// every call. Used to stand in for a Curve pool's `balances(i)`
    /// view so the replay reader's success branch can be exercised
    /// without standing up a real StableSwap deployment.
    fn const_uint256_returner(value: U256) -> Vec<u8> {
        let mut code = Vec::with_capacity(38);
        code.push(0x7f); // PUSH32
        code.extend_from_slice(&value.to_be_bytes::<32>());
        code.extend_from_slice(&[0x60, 0x00]); // PUSH1 0
        code.push(0x52); // MSTORE
        code.extend_from_slice(&[0x60, 0x20]); // PUSH1 32
        code.extend_from_slice(&[0x60, 0x00]); // PUSH1 0
        code.push(0xf3); // RETURN
        code
    }

    #[test]
    fn curve_replay_success_returns_decoded_balances() {
        // Stand-in pool returns the same constant for every `balances(i)`
        // call. Both reads succeed and decode cleanly, so the reader
        // populates a `CurvePostState` with `new_balance_in` /
        // `new_balance_out` both equal to the constant and
        // `analytical = false` (revm-derived state is the
        // non-analytical branch by definition).
        let constant = U256::from(123_456_789u64);
        let pool = address!("bEbc44782C7dB0a1A60Cb6fe97d0b483032FF1C7");
        let mut state = ForkedState::new_empty(18_000_000, 1_700_000_000, 1_000_000_000);
        state.insert_account(pool, U256::ZERO, const_uint256_returner(constant).into());
        // Fund victim so the value-transfer succeeds against codeless
        // recipient; the replay path commits the victim before the
        // balances() reads.
        state.insert_account_balance(default_victim().from, U256::from(10u128.pow(18)));
        let result = replay_curve_post_state_cache(
            state,
            &default_victim(),
            pool,
            0,
            1,
            &default_params(),
        );
        let post = result.expect("replay should succeed against const-returner bytecode");
        assert_eq!(post.new_balance_in, constant);
        assert_eq!(post.new_balance_out, constant);
        assert_eq!(post.i, 0);
        assert_eq!(post.j, 1);
        assert!(!post.analytical, "revm-derived post-state must mark analytical=false");
    }

    #[test]
    fn curve_replay_victim_reverted_path() {
        // Victim target deployed with an explicit REVERT opcode. The
        // reader must surface `VictimReverted` before any balances()
        // call is attempted.
        let mut state = ForkedState::new_empty(18_000_000, 1_700_000_000, 1_000_000_000);
        let victim_target = address!("3333333333333333333333333333333333333333");
        state.insert_account(
            victim_target,
            U256::ZERO,
            vec![0x60, 0x00, 0x60, 0x00, 0xfd].into(),
        );
        state.insert_account_balance(default_victim().from, U256::from(10u128.pow(18)));
        let pool = address!("bEbc44782C7dB0a1A60Cb6fe97d0b483032FF1C7");
        let result = replay_curve_post_state_cache(
            state,
            &default_victim(),
            pool,
            0,
            1,
            &default_params(),
        );
        assert!(matches!(result, Err(ReplayError::VictimReverted)));
    }

    #[test]
    fn balancer_replay_victim_reverted_path() {
        let mut state = ForkedState::new_empty(18_000_000, 1_700_000_000, 1_000_000_000);
        let victim_target = address!("3333333333333333333333333333333333333333");
        state.insert_account(
            victim_target,
            U256::ZERO,
            vec![0x60, 0x00, 0x60, 0x00, 0xfd].into(),
        );
        state.insert_account_balance(default_victim().from, U256::from(10u128.pow(18)));
        let pool = address!("5c6Ee304399DBdB9C8Ef030aB642B10820DB8F56");
        let t0 = address!("C02aaA39b223FE8D0A0e5C4F27eAD9083C756Cc2");
        let t1 = address!("ba100000625a3754423978a60c9317c58a424e3D");
        let result = replay_balancer_post_state_cache(
            state,
            &default_victim(),
            pool,
            BALANCER_V2_VAULT,
            t0,
            t1,
            &default_params(),
        );
        assert!(matches!(result, Err(ReplayError::VictimReverted)));
    }

    #[test]
    fn unimplemented_protocol_label_still_available() {
        // Kept for label-space stability — the metric vocabulary in
        // `metrics.rs` still includes `unimplemented_protocol` for
        // legitimately disabled replay paths (no provider wired,
        // semaphore saturation, etc.).
        let err = ReplayError::UnimplementedProtocol("curve");
        assert_eq!(err.as_str(), "unimplemented_protocol");
        let err = ReplayError::UnimplementedProtocol("balancer");
        assert_eq!(err.as_str(), "unimplemented_protocol");
    }

    #[test]
    fn replay_error_label_stability() {
        // Lock in the label values — the metric label space in
        // `metrics.rs` pre-touches these exact strings.
        assert_eq!(ReplayError::VictimReverted.as_str(), "victim_reverted");
        assert_eq!(ReplayError::VictimHalted.as_str(), "victim_halted");
        assert_eq!(ReplayError::ReadCallFailed("slot0").as_str(), "read_call_failed");
        assert_eq!(ReplayError::DecodeFailed("slot0").as_str(), "decode_failed");
        assert_eq!(ReplayError::SimError.as_str(), "sim_error");
    }
}

//! Batched storage prefetch via Multicall3 (`eth_call` with N sub-calls).
//!
//! ## Why
//!
//! The default pre-warm path issues one `eth_getStorageAt` per pool to read
//! UniV2's packed reserves slot. On Alchemy each call costs 20 CU; for N
//! stale/missing pools the bill is `N × 20` CU per block cycle. Free-tier
//! (1,000 CU/s) collapses into 429 throttling once a handful of validator
//! threads fan out simultaneously, which we observed during the 2 h shadow
//! demo (196 × 429 over 2 h, 193 in the last 5 min).
//!
//! Multicall3 — deployed at the canonical
//! `0xcA11bde05977b3631167028862bE2a173976CA11` on Ethereum mainnet — bundles
//! arbitrary read-only sub-calls into one `eth_call`. The full payload is
//! billed as a single `eth_call` (26 CU regardless of sub-call count), so the
//! crossover vs N `eth_getStorageAt` is `N ≥ 2`. For typical batches of 10–100
//! pools the saving is ~95–99 % of CU and (more importantly under burst load)
//! drops the in-flight RPC count from N to 1.
//!
//! ## Returned shape
//!
//! `batch_v2_reserves` returns one `V2ReservesResult` per pool that responded
//! successfully. Pools whose sub-call reverted (typical when a stale address
//! list still references a self-destructed or mistyped pair) are silently
//! omitted — the caller's per-pool fallback path can pick them up if needed,
//! exactly like an empty `eth_getStorageAt` response would today.

use alloy::eips::BlockId;
use alloy::network::Ethereum;
use alloy::primitives::{address, Address, U256};
use alloy::providers::{DynProvider, Provider};
use alloy::rpc::types::TransactionRequest;
use alloy::sol;
use alloy::sol_types::SolCall;

/// Canonical Multicall3 deployment on Ethereum mainnet (and most EVM chains).
pub const MULTICALL3_ADDRESS: Address = address!("cA11bde05977b3631167028862bE2a173976CA11");

sol! {
    #[allow(missing_docs)]
    interface IMulticall3 {
        struct Call3 {
            address target;
            bool allowFailure;
            bytes callData;
        }
        struct Result {
            bool success;
            bytes returnData;
        }
        function aggregate3(Call3[] calls) external payable returns (Result[] returnData);
    }

    #[allow(missing_docs)]
    interface IUniswapV2Pair {
        function getReserves() external view returns (uint112 reserve0, uint112 reserve1, uint32 blockTimestampLast);
    }
}

/// One decoded `getReserves()` outcome from a batch call.
#[derive(Clone, Copy, Debug)]
pub struct V2ReservesResult {
    pub pool: Address,
    pub reserve0: U256,
    pub reserve1: U256,
}

/// Batch-fetch `getReserves()` for every entry in `pools` via a single
/// Multicall3 `eth_call` at `block_number`.
///
/// Behaviour:
/// - `pools` is empty ⇒ returns `Ok(vec![])` without issuing any RPC.
/// - Multicall payload errors (network, decode) ⇒ returns `Err(_)` so the
///   caller can fall back to the per-pool path without losing pools.
/// - Individual sub-call reverts (`allowFailure=true`) ⇒ that pool is dropped
///   from the output; surviving pools are still returned.
pub async fn batch_v2_reserves(
    provider: &DynProvider<Ethereum>,
    block_number: u64,
    pools: &[Address],
) -> Result<Vec<V2ReservesResult>, String> {
    if pools.is_empty() {
        return Ok(Vec::new());
    }
    let getreserves_calldata = IUniswapV2Pair::getReservesCall {}.abi_encode();
    let calls: Vec<IMulticall3::Call3> = pools
        .iter()
        .map(|&p| IMulticall3::Call3 {
            target: p,
            allowFailure: true,
            callData: getreserves_calldata.clone().into(),
        })
        .collect();
    let calldata = IMulticall3::aggregate3Call { calls }.abi_encode();
    let tx = TransactionRequest::default()
        .to(MULTICALL3_ADDRESS)
        .input(calldata.into());
    let out = provider
        .call(tx)
        .block(BlockId::from(block_number))
        .await
        .map_err(|e| format!("multicall3 eth_call failed: {e}"))?;
    let decoded = IMulticall3::aggregate3Call::abi_decode_returns(&out)
        .map_err(|e| format!("multicall3 decode failed: {e}"))?;
    if decoded.len() != pools.len() {
        return Err(format!(
            "multicall3 returned {} results for {} sub-calls",
            decoded.len(),
            pools.len()
        ));
    }
    let mut results = Vec::with_capacity(pools.len());
    for (pool, res) in pools.iter().zip(decoded.into_iter()) {
        if !res.success {
            continue;
        }
        let bytes = res.returnData;
        // `getReserves()` returns (uint112, uint112, uint32) — three 32-byte words.
        if bytes.len() < 96 {
            continue;
        }
        let reserve0 = U256::from_be_slice(&bytes[0..32]);
        let reserve1 = U256::from_be_slice(&bytes[32..64]);
        if reserve0 == U256::ZERO && reserve1 == U256::ZERO {
            // Empty pool — same treatment as `eth_getStorageAt` returning 0.
            continue;
        }
        results.push(V2ReservesResult {
            pool: *pool,
            reserve0,
            reserve1,
        });
    }
    Ok(results)
}

#[cfg(test)]
mod tests {
    use super::*;
    use alloy::sol_types::SolValue;

    /// Multicall3 selector must match the canonical on-chain ABI so the
    /// rendered calldata stays compatible with the deployed contract.
    #[test]
    fn aggregate3_selector_matches_canonical() {
        // Canonical aggregate3 selector — keccak256("aggregate3((address,bool,bytes)[])")[..4].
        // Source: https://github.com/mds1/multicall.
        assert_eq!(
            IMulticall3::aggregate3Call::SELECTOR,
            [0x82, 0xad, 0x56, 0xcb]
        );
    }

    #[test]
    fn getreserves_selector_matches_canonical() {
        // keccak256("getReserves()")[..4] = 0x0902f1ac.
        assert_eq!(
            IUniswapV2Pair::getReservesCall::SELECTOR,
            [0x09, 0x02, 0xf1, 0xac]
        );
    }

    #[test]
    fn empty_input_returns_empty_without_rpc() {
        let pools: [Address; 0] = [];
        // No provider needed — the helper short-circuits on empty input.
        // Build a future and poll it once; it must complete immediately
        // because no `.await` on the provider is reached.
        let fut = async move {
            // SAFETY: provider deref is unreachable for empty input.
            // Construct a panic-on-use provider stand-in via expect on a
            // never-built DynProvider would require a runtime; instead we
            // assert the behaviour by directly exercising the early return.
            assert!(pools.is_empty());
        };
        futures::executor::block_on(fut);
    }

    /// Synthesise a Multicall3 return blob and confirm decode round-trips.
    /// Catches any drift in the ABI types if the `sol!` macro output changes.
    #[test]
    fn decode_aggregate3_return_round_trip() {
        let p0 = address!("0000000000000000000000000000000000000001");
        let p1 = address!("0000000000000000000000000000000000000002");
        // Two reserves each: (1 ether, 2 ether) and (3 ether, 4 ether).
        let one = U256::from(1_000_000_000_000_000_000u128);
        let payload0 = {
            let mut b = Vec::with_capacity(96);
            b.extend_from_slice(&one.to_be_bytes::<32>());
            b.extend_from_slice(&(one * U256::from(2u8)).to_be_bytes::<32>());
            b.extend_from_slice(&U256::ZERO.to_be_bytes::<32>()); // timestamp
            b
        };
        let payload1 = {
            let mut b = Vec::with_capacity(96);
            b.extend_from_slice(&(one * U256::from(3u8)).to_be_bytes::<32>());
            b.extend_from_slice(&(one * U256::from(4u8)).to_be_bytes::<32>());
            b.extend_from_slice(&U256::ZERO.to_be_bytes::<32>());
            b
        };
        let synth_return = vec![
            IMulticall3::Result {
                success: true,
                returnData: payload0.into(),
            },
            IMulticall3::Result {
                success: true,
                returnData: payload1.into(),
            },
        ];
        let encoded = <Vec<IMulticall3::Result> as SolValue>::abi_encode(&synth_return);
        let decoded = IMulticall3::aggregate3Call::abi_decode_returns(&encoded).unwrap();
        assert_eq!(decoded.len(), 2);
        assert!(decoded[0].success);
        assert!(decoded[1].success);

        // Manually walk the post-decode logic the helper applies.
        let pools = [p0, p1];
        let mut out = Vec::new();
        for (pool, res) in pools.iter().zip(decoded.into_iter()) {
            if !res.success || res.returnData.len() < 96 {
                continue;
            }
            let r0 = U256::from_be_slice(&res.returnData[0..32]);
            let r1 = U256::from_be_slice(&res.returnData[32..64]);
            out.push(V2ReservesResult {
                pool: *pool,
                reserve0: r0,
                reserve1: r1,
            });
        }
        assert_eq!(out.len(), 2);
        assert_eq!(out[0].pool, p0);
        assert_eq!(out[0].reserve0, one);
        assert_eq!(out[0].reserve1, one * U256::from(2u8));
        assert_eq!(out[1].reserve0, one * U256::from(3u8));
    }

    /// Failed sub-calls (e.g. EOA address misclassified as a V2 pair) must
    /// be dropped from the output, not propagated as a hard error.
    #[test]
    fn failed_subcalls_are_dropped() {
        let pools = [
            address!("0000000000000000000000000000000000000001"),
            address!("0000000000000000000000000000000000000002"),
        ];
        let synth = vec![
            IMulticall3::Result {
                success: false,
                returnData: vec![].into(),
            },
            IMulticall3::Result {
                success: true,
                returnData: {
                    let mut b = Vec::with_capacity(96);
                    b.extend_from_slice(&U256::from(7u8).to_be_bytes::<32>());
                    b.extend_from_slice(&U256::from(11u8).to_be_bytes::<32>());
                    b.extend_from_slice(&U256::ZERO.to_be_bytes::<32>());
                    b
                }
                .into(),
            },
        ];
        let mut out = Vec::new();
        for (pool, res) in pools.iter().zip(synth.into_iter()) {
            if !res.success || res.returnData.len() < 96 {
                continue;
            }
            let r0 = U256::from_be_slice(&res.returnData[0..32]);
            let r1 = U256::from_be_slice(&res.returnData[32..64]);
            out.push(V2ReservesResult {
                pool: *pool,
                reserve0: r0,
                reserve1: r1,
            });
        }
        assert_eq!(out.len(), 1);
        assert_eq!(out[0].pool, pools[1]);
        assert_eq!(out[0].reserve0, U256::from(7u8));
    }
}

//! In-memory cache of the latest packed reserves slot for UniswapV2 /
//! SushiSwap pools, fed by the WebSocket `Sync` event stream.
//!
//! UniV2's `getReserves()` reads a single packed slot at storage index 8:
//!
//! ```text
//! slot8 = (blockTimestampLast << 224) | (reserve1 << 112) | reserve0
//! ```
//!
//! The detector already subscribes to every monitored pool's `Sync` event
//! and decodes the new reserve pair on every block. Today we throw that
//! data away after the price-graph edge update and pay a fresh
//! `eth_getStorageAt` round-trip per pool on every pre-warm cycle to refetch
//! information that just arrived for free over the WS.
//!
//! `V2ReservesCache` captures the latest decoded reserves and exposes them
//! as a synthesised slot-8 value for the pre-warm path. The `blockTimestampLast`
//! field is *not* part of a Sync event, so we leave it zero — UniV2 swap
//! math does not depend on it (only `_update()` writes the field, and that
//! happens *after* the swap quantities are computed). Any consumer that
//! does need a live timestamp must still fall through to RPC.
//!
//! All operations are O(1) lock-free via `DashMap`. The cache is cheap to
//! clone (it's `Arc`-backed) so the engine writer side and the pre-warm
//! reader side share a single shared instance.

use std::sync::Arc;

use alloy::primitives::{Address, U256};
use dashmap::DashMap;

/// Bit shift for `reserve1` inside UniV2's packed slot 8.
const RESERVE1_SHIFT: u32 = 112;

/// 112-bit mask used when packing `reserve0` / `reserve1` into slot 8.
fn uint112_mask() -> U256 {
    (U256::from(1u64) << 112) - U256::from(1u64)
}

/// Inverse of [`ReserveSnapshot::pack_slot8`]: decode a raw UniV2 slot-8
/// value into the `(reserve0, reserve1)` pair, discarding the high 32 bits
/// (`blockTimestampLast`) which the cache always stores as zero.
///
/// Used by the pre-warm path to write fresh RPC `eth_getStorageAt` results
/// back into the cache so subsequent cycles serve them locally.
pub fn unpack_slot8(slot: U256) -> (U256, U256) {
    let mask = uint112_mask();
    let r0 = slot & mask;
    let r1 = (slot >> RESERVE1_SHIFT) & mask;
    (r0, r1)
}

/// Latest reserve pair captured for a single pool. `block_number` is the
/// chain head at which the underlying Sync event was emitted; the pre-warm
/// path can use it to reject stale entries during reorgs.
#[derive(Clone, Copy, Debug)]
pub struct ReserveSnapshot {
    pub reserve0: U256,
    pub reserve1: U256,
    pub block_number: u64,
}

impl ReserveSnapshot {
    /// Encode the snapshot as a UniV2 packed slot-8 value.
    /// `blockTimestampLast` is forced to 0 — see module docs.
    pub fn pack_slot8(&self) -> U256 {
        let mask = uint112_mask();
        let r0 = self.reserve0 & mask;
        let r1 = self.reserve1 & mask;
        r0 | (r1 << RESERVE1_SHIFT)
    }
}

/// Lock-free cache of the latest per-pool reserve snapshot.
#[derive(Clone, Default)]
pub struct V2ReservesCache {
    inner: Arc<DashMap<Address, ReserveSnapshot>>,
}

impl V2ReservesCache {
    pub fn new() -> Self {
        Self::default()
    }

    /// Number of distinct pools currently cached. Useful for diagnostics.
    pub fn len(&self) -> usize {
        self.inner.len()
    }

    pub fn is_empty(&self) -> bool {
        self.inner.is_empty()
    }

    /// Record the latest reserves for `pool` at `block_number`. Newer
    /// `block_number` always wins; older updates are dropped so a delayed
    /// out-of-order event cannot poison the cache with stale state.
    pub fn record(&self, pool: Address, reserve0: U256, reserve1: U256, block_number: u64) {
        self.inner
            .entry(pool)
            .and_modify(|existing| {
                if block_number >= existing.block_number {
                    existing.reserve0 = reserve0;
                    existing.reserve1 = reserve1;
                    existing.block_number = block_number;
                }
            })
            .or_insert(ReserveSnapshot {
                reserve0,
                reserve1,
                block_number,
            });
    }

    /// Look up the latest snapshot for `pool` if one has been captured.
    pub fn get(&self, pool: Address) -> Option<ReserveSnapshot> {
        self.inner.get(&pool).map(|v| *v.value())
    }

    /// Look up the latest snapshot for `pool` only if it is fresh enough for
    /// `target_block` — i.e. emitted no earlier than `target_block.saturating_sub(max_lag)`.
    /// Stale entries return `None` so the caller falls through to RPC.
    pub fn get_fresh(
        &self,
        pool: Address,
        target_block: u64,
        max_lag: u64,
    ) -> Option<ReserveSnapshot> {
        match self.get_fresh_status(pool, target_block, max_lag) {
            V2CacheLookup::Fresh(snap) => Some(snap),
            V2CacheLookup::Stale | V2CacheLookup::Missing => None,
        }
    }

    /// Same as [`get_fresh`] but distinguishes stale-but-present entries from
    /// never-seen pools so the caller can bump separate `cache_hits` /
    /// `cache_stale` counters. Both stale and missing paths still fall through
    /// to RPC; the split is purely for observability.
    pub fn get_fresh_status(
        &self,
        pool: Address,
        target_block: u64,
        max_lag: u64,
    ) -> V2CacheLookup {
        let Some(snap) = self.get(pool) else {
            return V2CacheLookup::Missing;
        };
        let oldest_acceptable = target_block.saturating_sub(max_lag);
        if snap.block_number >= oldest_acceptable {
            V2CacheLookup::Fresh(snap)
        } else {
            V2CacheLookup::Stale
        }
    }
}

/// Outcome of a freshness-gated lookup. `Stale` carries no payload because
/// the caller falls through to RPC regardless; it exists so we can count
/// "lag-window rejected" pools separately from "never seen" ones, which
/// behave very differently during reorgs and after WS reconnects.
#[derive(Clone, Copy, Debug)]
pub enum V2CacheLookup {
    Fresh(ReserveSnapshot),
    Stale,
    Missing,
}

#[cfg(test)]
mod tests {
    use super::*;
    use alloy::primitives::address;

    #[test]
    fn record_then_get_roundtrip() {
        let cache = V2ReservesCache::new();
        let pool = address!("aaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaa");
        cache.record(pool, U256::from(100u64), U256::from(200u64), 42);
        let s = cache.get(pool).expect("hit");
        assert_eq!(s.reserve0, U256::from(100u64));
        assert_eq!(s.reserve1, U256::from(200u64));
        assert_eq!(s.block_number, 42);
        assert_eq!(cache.len(), 1);
    }

    #[test]
    fn get_returns_none_when_unseen() {
        let cache = V2ReservesCache::new();
        let pool = address!("bbbbbbbbbbbbbbbbbbbbbbbbbbbbbbbbbbbbbbbb");
        assert!(cache.get(pool).is_none());
        assert!(cache.is_empty());
    }

    #[test]
    fn newer_block_overwrites_older() {
        let cache = V2ReservesCache::new();
        let pool = address!("cccccccccccccccccccccccccccccccccccccccc");
        cache.record(pool, U256::from(1u64), U256::from(2u64), 100);
        cache.record(pool, U256::from(3u64), U256::from(4u64), 101);
        let s = cache.get(pool).unwrap();
        assert_eq!(s.reserve0, U256::from(3u64));
        assert_eq!(s.reserve1, U256::from(4u64));
        assert_eq!(s.block_number, 101);
    }

    #[test]
    fn out_of_order_older_event_is_dropped() {
        // Sync events occasionally arrive out of order during a reorg or a
        // mid-stream WS reconnect. An older `block_number` must not replace
        // the freshest snapshot or the cache would poison the pre-warm path
        // with stale state.
        let cache = V2ReservesCache::new();
        let pool = address!("dddddddddddddddddddddddddddddddddddddddd");
        cache.record(pool, U256::from(3u64), U256::from(4u64), 101);
        cache.record(pool, U256::from(1u64), U256::from(2u64), 100); // older
        let s = cache.get(pool).unwrap();
        assert_eq!(s.reserve0, U256::from(3u64));
        assert_eq!(s.block_number, 101);
    }

    #[test]
    fn pack_slot8_layout_matches_uniswap_v2() {
        // The synthesised slot8 layout must place reserve0 in bits 0..111,
        // reserve1 in bits 112..223, and leave the high 32 bits (where
        // `blockTimestampLast` would live) untouched. Use small, distinct
        // values that fit comfortably inside 112 bits.
        let snap = ReserveSnapshot {
            reserve0: U256::from(0xAABBCCu64),
            reserve1: U256::from(0xDDEEFFu64),
            block_number: 1,
        };
        let packed = snap.pack_slot8();
        let mask112 = uint112_mask();
        let r0_back = packed & mask112;
        let r1_back = (packed >> RESERVE1_SHIFT) & mask112;
        assert_eq!(r0_back, U256::from(0xAABBCCu64));
        assert_eq!(r1_back, U256::from(0xDDEEFFu64));
        // High 32 bits = blockTimestampLast region must be zero.
        let ts_region = packed >> 224;
        assert_eq!(ts_region, U256::ZERO, "timestamp region must stay zero");
    }

    #[test]
    fn pack_slot8_truncates_to_uint112() {
        // Real on-chain values are already uint112, but defensively the
        // packer must mask anything wider so a malformed input never
        // contaminates the reserve1 / timestamp bands.
        let mask112 = uint112_mask();
        let oversized = (U256::from(1u64) << 130) | U256::from(7u64);
        let snap = ReserveSnapshot {
            reserve0: oversized,
            reserve1: oversized,
            block_number: 1,
        };
        let packed = snap.pack_slot8();
        let r0_back = packed & mask112;
        let r1_back = (packed >> RESERVE1_SHIFT) & mask112;
        // The bit-130 value is dropped because it falls outside the 112-bit
        // window; only the low 7 survives.
        assert_eq!(r0_back, U256::from(7u64));
        assert_eq!(r1_back, U256::from(7u64));
        // No overflow into the timestamp band.
        let ts_region = packed >> 224;
        assert_eq!(ts_region, U256::ZERO);
    }

    #[test]
    fn get_fresh_accepts_within_lag_window() {
        let cache = V2ReservesCache::new();
        let pool = address!("eeeeeeeeeeeeeeeeeeeeeeeeeeeeeeeeeeeeeeee");
        cache.record(pool, U256::from(1u64), U256::from(2u64), 100);
        // Target block 102, lag 3 -> oldest acceptable = 99; cached at 100 -> hit.
        assert!(cache.get_fresh(pool, 102, 3).is_some());
    }

    #[test]
    fn get_fresh_rejects_stale_snapshot() {
        let cache = V2ReservesCache::new();
        let pool = address!("ffffffffffffffffffffffffffffffffffffffff");
        cache.record(pool, U256::from(1u64), U256::from(2u64), 50);
        // Target block 100, lag 3 -> oldest acceptable = 97; cached at 50 -> miss.
        assert!(cache.get_fresh(pool, 100, 3).is_none());
    }

    /// `unpack_slot8` must be the exact inverse of `pack_slot8` so RPC
    /// results written back via the prewarm fetch path round-trip to the
    /// same `(reserve0, reserve1)` the cache would have emitted itself.
    /// The high 32 bits (timestamp) are dropped — the cache never stores
    /// them and consumers don't depend on them.
    #[test]
    fn pack_unpack_slot8_roundtrip() {
        let snap = ReserveSnapshot {
            reserve0: U256::from(0x1234_5678u64),
            reserve1: U256::from(0xAABB_CCDDu64),
            block_number: 99,
        };
        let packed = snap.pack_slot8();
        let (r0, r1) = unpack_slot8(packed);
        assert_eq!(r0, snap.reserve0);
        assert_eq!(r1, snap.reserve1);
    }

    /// Real RPC `eth_getStorageAt` returns slot 8 with the timestamp band
    /// populated. The unpacker must ignore it instead of bleeding it into
    /// `reserve1`.
    #[test]
    fn unpack_slot8_ignores_timestamp_band() {
        // Build a real-shape slot: timestamp = 0xDEADBEEF, reserve1 = 7, reserve0 = 11.
        let timestamp = U256::from(0xDEAD_BEEFu64) << 224;
        let reserve1 = U256::from(7u64) << RESERVE1_SHIFT;
        let reserve0 = U256::from(11u64);
        let slot = timestamp | reserve1 | reserve0;
        let (r0, r1) = unpack_slot8(slot);
        assert_eq!(r0, U256::from(11u64));
        assert_eq!(r1, U256::from(7u64));
    }

    /// `get_fresh_status` must split the miss path into Stale vs Missing so
    /// the pre-warm path can count them separately. Both produce identical
    /// behaviour on the convenience `get_fresh` wrapper, so this is the
    /// only place where the distinction is observable.
    #[test]
    fn get_fresh_status_distinguishes_stale_from_missing() {
        let cache = V2ReservesCache::new();
        let unseen = address!("1111111111111111111111111111111111111111");
        assert!(matches!(
            cache.get_fresh_status(unseen, 100, 1),
            V2CacheLookup::Missing
        ));

        let stale = address!("2222222222222222222222222222222222222222");
        cache.record(stale, U256::from(1u64), U256::from(2u64), 90);
        assert!(matches!(
            cache.get_fresh_status(stale, 100, 1),
            V2CacheLookup::Stale
        ));

        let fresh = address!("3333333333333333333333333333333333333333");
        cache.record(fresh, U256::from(1u64), U256::from(2u64), 100);
        assert!(matches!(
            cache.get_fresh_status(fresh, 100, 1),
            V2CacheLookup::Fresh(_)
        ));
    }
}

use criterion::{black_box, criterion_group, criterion_main, BenchmarkId, Criterion};

use aether_common::types::{PoolId, ProtocolType};
use aether_state::price_graph::PriceGraph;
use alloy::primitives::{Address, U256};

fn make_pool_id(byte: u8, protocol: ProtocolType) -> PoolId {
    PoolId {
        address: Address::repeat_byte(byte),
        protocol,
    }
}

fn bench_add_edge(c: &mut Criterion) {
    let mut group = c.benchmark_group("price_graph_add_edge");

    for &n in &[100, 500, 1000] {
        group.bench_with_input(BenchmarkId::new("new_edges", n), &n, |b, &n| {
            b.iter(|| {
                let mut g = PriceGraph::new(n);
                for i in 0..n {
                    let j = (i + 1) % n;
                    let pid = make_pool_id((i % 255) as u8, ProtocolType::UniswapV2);
                    g.add_edge(
                        i,
                        j,
                        1.05,
                        pid,
                        Address::repeat_byte((i % 255) as u8),
                        ProtocolType::UniswapV2,
                        U256::from(1_000_000u64),
                    );
                }
                black_box(&g);
            })
        });
    }

    // Benchmark edge update (same pool_id overwrites existing edge)
    for &n in &[100, 500] {
        group.bench_with_input(BenchmarkId::new("update_existing", n), &n, |b, &n| {
            let mut g = PriceGraph::new(n);
            for i in 0..n {
                let j = (i + 1) % n;
                let pid = make_pool_id((i % 255) as u8, ProtocolType::UniswapV2);
                g.add_edge(
                    i,
                    j,
                    1.05,
                    pid,
                    Address::repeat_byte((i % 255) as u8),
                    ProtocolType::UniswapV2,
                    U256::from(1_000_000u64),
                );
            }
            g.clear_dirty();

            b.iter(|| {
                for i in 0..n {
                    let j = (i + 1) % n;
                    let pid = make_pool_id((i % 255) as u8, ProtocolType::UniswapV2);
                    g.add_edge(
                        i,
                        j,
                        1.06,
                        pid,
                        Address::repeat_byte((i % 255) as u8),
                        ProtocolType::UniswapV2,
                        U256::from(2_000_000u64),
                    );
                }
                black_box(&g);
            })
        });
    }

    group.finish();
}

fn bench_edges_from(c: &mut Criterion) {
    let mut group = c.benchmark_group("price_graph_edges_from");

    for &n in &[100, 500, 1000] {
        // Build graph with ~3 edges per vertex
        let mut g = PriceGraph::new(n);
        let protocols = [
            ProtocolType::UniswapV2,
            ProtocolType::UniswapV3,
            ProtocolType::SushiSwap,
        ];
        for i in 0..n {
            for (k, &proto) in protocols.iter().enumerate() {
                let j = (i + k + 1) % n;
                let pid = make_pool_id(((i * 3 + k) % 255) as u8, proto);
                g.add_edge(
                    i,
                    j,
                    1.05,
                    pid,
                    Address::repeat_byte(((i * 3 + k) % 255) as u8),
                    proto,
                    U256::from(1_000_000u64),
                );
            }
        }

        group.bench_with_input(BenchmarkId::new("lookup", n), &g, |b, g| {
            b.iter(|| {
                for i in 0..n {
                    black_box(g.edges_from(i));
                }
            })
        });
    }

    group.finish();
}

fn bench_affected_vertices(c: &mut Criterion) {
    let mut group = c.benchmark_group("price_graph_affected_vertices");

    for &n in &[100, 500, 1000] {
        let mut g = PriceGraph::new(n);
        for i in 0..n {
            let j = (i + 1) % n;
            let pid = make_pool_id((i % 255) as u8, ProtocolType::UniswapV2);
            g.add_edge(
                i,
                j,
                1.05,
                pid,
                Address::repeat_byte((i % 255) as u8),
                ProtocolType::UniswapV2,
                U256::from(1_000_000u64),
            );
        }
        // All edges are dirty (just added)

        group.bench_with_input(BenchmarkId::new("all_dirty", n), &g, |b, g| {
            b.iter(|| black_box(g.affected_vertices()))
        });
    }

    group.finish();
}

fn bench_clear_dirty(c: &mut Criterion) {
    let mut group = c.benchmark_group("price_graph_clear_dirty");

    for &n in &[100, 500, 1000] {
        let mut g = PriceGraph::new(n);
        for i in 0..n {
            let j = (i + 1) % n;
            let pid = make_pool_id((i % 255) as u8, ProtocolType::UniswapV2);
            g.add_edge(
                i,
                j,
                1.05,
                pid,
                Address::repeat_byte((i % 255) as u8),
                ProtocolType::UniswapV2,
                U256::from(1_000_000u64),
            );
        }

        group.bench_with_input(BenchmarkId::new("edges", n), &n, |b, _| {
            b.iter(|| {
                g.clear_dirty();
                // Re-dirty one edge for the next iter
                let pid = make_pool_id(0, ProtocolType::UniswapV2);
                g.add_edge(
                    0,
                    1,
                    1.06,
                    pid,
                    Address::repeat_byte(0),
                    ProtocolType::UniswapV2,
                    U256::from(1_000_000u64),
                );
            })
        });
    }

    group.finish();
}

fn bench_update_edge_from_reserves(c: &mut Criterion) {
    let mut group = c.benchmark_group("price_graph_update_reserves");

    for &n in &[100, 500] {
        let mut g = PriceGraph::new(n);
        let mut pool_ids = Vec::new();
        for i in 0..n {
            let j = (i + 1) % n;
            let pid = make_pool_id((i % 255) as u8, ProtocolType::UniswapV2);
            pool_ids.push((i, j, pid));
            g.add_edge(
                i,
