    #[test]
    fn test_decimal_correction_usdc_weth_v2() {
        // Realistic balanced mainnet-ish USDC/WETH V2 pool at ~3000 USDC/WETH.
        // vertex 0 = USDC (6 decimals), vertex 1 = WETH (18 decimals).
        // Reserves in raw base units:
        //   USDC: 3,000,000 * 1e6  = 3_000_000_000_000
        //   WETH: 1,000     * 1e18 = 1_000_000_000_000_000_000_000
        // Human price = 3,000,000 USDC / 1,000 WETH = 3000 USDC per WETH.
        let mut g = PriceGraph::new(2);
        g.set_token_decimals(0, 6); // USDC
        g.set_token_decimals(1, 18); // WETH

        let pool_id = make_pool_id(1, ProtocolType::UniswapV2);
        // USDC -> WETH edge and WETH -> USDC edge.
        g.add_edge(
            0,
            1,
            1.0,
            pool_id,
            Address::repeat_byte(1),
            ProtocolType::UniswapV2,
            U256::from(1u64),
        );
        g.add_edge(
            1,
            0,
            1.0,
            pool_id,
            Address::repeat_byte(1),
            ProtocolType::UniswapV2,
            U256::from(1u64),
        );

        let usdc_reserve = 3_000_000_000_000.0_f64; // 3e6 * 1e6
        let weth_reserve = 1_000_000_000_000_000_000_000.0_f64; // 1e3 * 1e18
        let fee = 0.997_f64;

        // USDC(0) -> WETH(1): rate ~ (1/3000) * fee in human units.
        g.update_edge_from_reserves(0, 1, pool_id, usdc_reserve, weth_reserve, fee);
        // WETH(1) -> USDC(0): rate ~ 3000 * fee in human units.
        g.update_edge_from_reserves(1, 0, pool_id, weth_reserve, usdc_reserve, fee);

        // Recover human rates from stored weights (-ln(rate)).
        let usdc_to_weth_rate = (-g.edges_from(0)[0].weight).exp();
        let weth_to_usdc_rate = (-g.edges_from(1)[0].weight).exp();

        // Each rate must be in a sane band, NOT off by ~1e12.
        let expected_usdc_to_weth = (1.0 / 3000.0) * fee;
        let expected_weth_to_usdc = 3000.0 * fee;
        assert!(
            (usdc_to_weth_rate - expected_usdc_to_weth).abs() / expected_usdc_to_weth < 1e-9,
            "USDC->WETH human rate off: got {usdc_to_weth_rate}, want ~{expected_usdc_to_weth}"
        );
        assert!(
            (weth_to_usdc_rate - expected_weth_to_usdc).abs() / expected_weth_to_usdc < 1e-9,
            "WETH->USDC human rate off: got {weth_to_usdc_rate}, want ~{expected_weth_to_usdc}"
        );

        // Round-trip product must be ~fee^2 (≈ 0.997^2 ≈ 0.994), NOT ~1e±12.
        let product = usdc_to_weth_rate * weth_to_usdc_rate;
        assert!(
            (product - fee * fee).abs() < 1e-9,
            "round-trip product should be ~fee^2 ({}), got {product}",
            fee * fee
        );
    }

    #[test]
    fn test_decimal_correction_v3_synthetic_mapping() {
        // Regression for the V3 synthetic mapping that triggered the live
        // phantom-profit bug: (reserve_in, reserve_out) = (1.0, raw_spot).
        // raw_spot = (sqrt_price / 2^96)^2 ~ token1_base_per_token0_base.
        //
        // For a USDC(token0, 6 dec) / WETH(token1, 18 dec) V3 pool priced at
        // ~3000 USDC/WETH, raw_spot (WETH-base per USDC-base) ~ token1/token0.
        // Human price WETH per USDC = (1/3000); in base units that is
        //   raw_spot = (1/3000) * 10^(dec1 - dec0) = (1/3000) * 1e12.
        // The edge direction here is USDC(0) -> WETH(1), so the corrected human
        // rate must be ~ (1/3000) * fee, NOT off by 1e12.
        let mut g = PriceGraph::new(2);
        g.set_token_decimals(0, 6); // USDC = token0
        g.set_token_decimals(1, 18); // WETH = token1

        let pool_id = make_pool_id(2, ProtocolType::UniswapV3);
        g.add_edge(
            0,
            1,
            1.0,
            pool_id,
            Address::repeat_byte(2),
            ProtocolType::UniswapV3,
            U256::from(1u64),
        );

        let fee = 0.997_f64;
        // raw_spot in base units: (1/3000) human * 10^(18-6) = (1/3000) * 1e12.
        let raw_spot = (1.0 / 3000.0) * 1e12;

        // V3 synthetic: reserve_in = 1.0 (dimensionless), reserve_out = raw_spot.
        g.update_edge_from_reserves(0, 1, pool_id, 1.0, raw_spot, fee);

        let human_rate = (-g.edges_from(0)[0].weight).exp();
        let expected = (1.0 / 3000.0) * fee;
        assert!(
            (human_rate - expected).abs() / expected < 1e-9,
            "V3 synthetic USDC->WETH human rate off: got {human_rate}, want ~{expected} (must NOT carry 1e12)"
        );
        // Sanity: a 1e12-off bug would put human_rate near 3.3e8; assert nowhere close.
        assert!(human_rate < 1.0, "human rate must be sub-1, got {human_rate}");
    }

    // --------------- Minimum-liquidity floor ---------------

    /// Build a single WETH-paired V2 pool (vertex 0 = some token, vertex 1 =
    /// WETH) with both directional placeholder edges in place, ready for a
    /// `update_edge_from_reserves` call. Returns the graph and the pool_id.
    fn build_weth_paired_pool(weth_decimals: u8) -> (PriceGraph, PoolId) {
        let mut g = PriceGraph::new(2);
        g.set_token_decimals(0, 18); // arbitrary token
        g.set_token_decimals(1, weth_decimals); // WETH
        let pool_id = make_pool_id(1, ProtocolType::UniswapV2);
        g.add_edge(0, 1, 1.0, pool_id, Address::repeat_byte(1), ProtocolType::UniswapV2, U256::from(1u64));
        g.add_edge(1, 0, 1.0, pool_id, Address::repeat_byte(1), ProtocolType::UniswapV2, U256::from(1u64));
        (g, pool_id)
    }

    #[test]
    fn test_floor_filters_low_weth_reserve() {
        // WETH-side human reserve = 0.5 WETH < floor 1.0 → filtered.
        let (mut g, pool_id) = build_weth_paired_pool(18);
        g.set_weth_vertex(1);
        g.set_min_liquidity_weth(1.0);

        // 0.5 WETH raw = 5e17 wei on the WETH side (vertex 1 = `to` for 0->1).
        let token_reserve = 1_000_000_000_000_000_000.0_f64; // 1.0 token
        let weth_reserve = 500_000_000_000_000_000.0_f64; // 0.5 WETH
        g.update_edge_from_reserves(0, 1, pool_id, token_reserve, weth_reserve, 0.997);
        g.update_edge_from_reserves(1, 0, pool_id, weth_reserve, token_reserve, 0.997);

        // Both directions must be filtered (each carries the same dead pool).
        assert!(g.edges_from(0)[0].filtered, "0->1 edge should be filtered");
        assert!(g.edges_from(1)[0].filtered, "1->0 edge should be filtered");
        // Mirror in all_edges must agree.
        assert!(g.all_edges().iter().all(|e| e.filtered));
    }

    #[test]
    fn test_floor_passes_high_weth_reserve() {
        // WETH-side human reserve = 10 WETH > floor 1.0 → not filtered.
        let (mut g, pool_id) = build_weth_paired_pool(18);
        g.set_weth_vertex(1);
        g.set_min_liquidity_weth(1.0);

        let token_reserve = 30_000_000_000_000_000_000_000.0_f64; // 30000 token
        let weth_reserve = 10_000_000_000_000_000_000.0_f64; // 10 WETH
        g.update_edge_from_reserves(0, 1, pool_id, token_reserve, weth_reserve, 0.997);
        g.update_edge_from_reserves(1, 0, pool_id, weth_reserve, token_reserve, 0.997);

        assert!(!g.edges_from(0)[0].filtered, "0->1 edge should not be filtered");
        assert!(!g.edges_from(1)[0].filtered, "1->0 edge should not be filtered");
        assert!(g.all_edges().iter().all(|e| !e.filtered));
    }

    #[test]
    fn test_floor_ignores_non_weth_pool() {
        // Neither vertex is WETH (weth_vertex points at a third vertex) → never
        // filtered regardless of how tiny the reserves are.
        let mut g = PriceGraph::new(3);
        g.set_token_decimals(0, 18);
        g.set_token_decimals(1, 18);
        g.set_weth_vertex(2); // WETH is vertex 2, not part of this pool
        g.set_min_liquidity_weth(1.0);

        let pool_id = make_pool_id(1, ProtocolType::UniswapV2);
        g.add_edge(0, 1, 1.0, pool_id, Address::repeat_byte(1), ProtocolType::UniswapV2, U256::from(1u64));
        // Tiny reserves on both sides — would be filtered if this were WETH-paired.
        g.update_edge_from_reserves(0, 1, pool_id, 1.0, 1.0, 0.997);

        assert!(!g.edges_from(0)[0].filtered, "non-WETH pool must never be floored");
    }

    #[test]
    fn test_floor_disabled_when_weth_vertex_unset() {
        // weth_vertex None → backward-compatible, never filtered.
        let (mut g, pool_id) = build_weth_paired_pool(18);
        g.set_min_liquidity_weth(1.0); // floor set, but no weth_vertex
        g.update_edge_from_reserves(0, 1, pool_id, 1.0, 1.0, 0.997);
        assert!(!g.edges_from(0)[0].filtered);
    }

    #[test]
    fn test_floor_disabled_when_floor_zero() {
        // min_liquidity_weth 0.0 (default) → never filtered even with weth_vertex.
        let (mut g, pool_id) = build_weth_paired_pool(18);
        g.set_weth_vertex(1);
        // Leave floor at its 0.0 default.
        assert_eq!(g.min_liquidity_weth(), 0.0);
        g.update_edge_from_reserves(0, 1, pool_id, 1.0, 1.0, 0.997);
        assert!(!g.edges_from(0)[0].filtered);
    }

    #[test]
    fn test_floor_decimal_aware_conversion() {
        // WETH is 18-dec: raw 5e17 wei = 0.5 WETH < floor 1.0 → filtered.
        // Verifies the human conversion divides by 10^decimals correctly.
        let (mut g, pool_id) = build_weth_paired_pool(18);
        g.set_weth_vertex(1);
        g.set_min_liquidity_weth(1.0);

        // WETH side (vertex 1) is `to` for the 0->1 direction.
        let weth_raw = 500_000_000_000_000_000.0_f64; // 5e17 wei = 0.5 WETH
        g.update_edge_from_reserves(0, 1, pool_id, 1.0e18, weth_raw, 0.997);
        assert!(
            g.edges_from(0)[0].filtered,
            "0.5 WETH (raw 5e17) must be below floor 1.0 after decimal conversion"
        );

        // Bump just above the floor: 1.5 WETH = 1.5e18 wei → not filtered.
        let weth_raw_ok = 1_500_000_000_000_000_000.0_f64;
        g.update_edge_from_reserves(0, 1, pool_id, 1.0e18, weth_raw_ok, 0.997);
        assert!(
            !g.edges_from(0)[0].filtered,
            "1.5 WETH must be above floor 1.0 after decimal conversion"
        );
    }

    #[test]
    fn test_add_edge_initializes_filtered_false() {
        let mut g = PriceGraph::new(2);
        let pool_id = make_pool_id(1, ProtocolType::UniswapV2);
        g.add_edge(0, 1, 2.0, pool_id, Address::repeat_byte(1), ProtocolType::UniswapV2, U256::from(1u64));
        assert!(!g.all_edges()[0].filtered, "placeholder edge must start unfiltered");
    }

    #[test]
    fn test_floor_skips_v3_when_weth_is_to_side() {
        // Regression: WETH-paired V3 pools carry the synthetic
        // `(reserve_in, reserve_out) = (1.0, raw_spot)` seed. When WETH
        // is the `to` side and the pair has decimal mismatch (e.g.
        // USDC(6) / WETH(18)), `raw_spot / 1e18` is ≈ 0, which the
        // legacy floor wrongly interpreted as "below the minimum WETH
        // reserve" and filtered the edge. The V3 carve-out skips that
        // computation entirely.
        let mut g = PriceGraph::new(2);
        g.set_token_decimals(0, 6); // USDC = token0
        g.set_token_decimals(1, 18); // WETH = token1
        g.set_weth_vertex(1);
        g.set_min_liquidity_weth(1.0);

        let pool_id = PoolId {
            address: Address::repeat_byte(2),
            protocol: ProtocolType::UniswapV3,
        };
        g.add_edge(0, 1, 1.0, pool_id, Address::repeat_byte(2), ProtocolType::UniswapV3, U256::ZERO);

        // Realistic V3 USDC->WETH synthetic seed: spot in raw base units
        // = (1/3000) human * 10^(18-6) = (1/3000) * 1e12 ≈ 3.33e8.
        let raw_spot = (1.0 / 3000.0) * 1e12;
        g.update_edge_from_reserves(0, 1, pool_id, 1.0, raw_spot, 0.997);

        assert!(
            !g.edges_from(0)[0].filtered,
            "deep V3 WETH-paired pool must not be filtered by the min_liquidity_weth floor"
        );
    }

    #[test]
    fn test_floor_skips_v3_when_weth_is_from_side() {
        // Symmetric direction: WETH on the `from` side. The synthetic
        // seed makes `reserve_in == 1.0`, which divided by 1e18 is
        // dust — would wrongly trip the floor without the V3 carve-out.
        let mut g = PriceGraph::new(2);
        g.set_token_decimals(0, 18); // WETH = token0
        g.set_token_decimals(1, 6); // USDC = token1
        g.set_weth_vertex(0);
        g.set_min_liquidity_weth(1.0);

        let pool_id = PoolId {
            address: Address::repeat_byte(3),
            protocol: ProtocolType::UniswapV3,
        };
        g.add_edge(0, 1, 1.0, pool_id, Address::repeat_byte(3), ProtocolType::UniswapV3, U256::ZERO);

        // WETH->USDC: synthetic reserve_in = 1.0 (the WETH side), real
        // spot on the output side. The exact spot value is irrelevant
        // for the floor; what matters is the V3 carve-out skipping the
        // human conversion altogether.
        g.update_edge_from_reserves(0, 1, pool_id, 1.0, 3000.0 * 1e12, 0.997);

        assert!(
            !g.edges_from(0)[0].filtered,
            "deep V3 WETH-paired pool (WETH on from side) must not be filtered"
        );
    }

    #[test]
    fn test_floor_still_applies_to_v2_weth_pool() {
        // Negative regression: the V3 carve-out must not weaken the floor
        // for V2/Sushi/Curve/Balancer/Bancor — those pools carry real
        // base-unit reserves and the floor remains the no-oracle TVL
        // proxy that catches drained or stub WETH pools.
        let (mut g, _v2_pool) = build_weth_paired_pool(18);
        g.set_weth_vertex(1);
        g.set_min_liquidity_weth(1.0);

        let v2_pool_id = PoolId {
            address: Address::repeat_byte(4),
            protocol: ProtocolType::UniswapV2,
        };
        // Overwrite with our explicit V2 pool to be unambiguous about protocol.
        g.add_edge(0, 1, 1.0, v2_pool_id, Address::repeat_byte(4), ProtocolType::UniswapV2, U256::ZERO);

        // 0.5 WETH on the WETH side (raw 5e17), one token unit on the
        // other side. Below the 1.0 WETH floor → must still be filtered.
        let weth_raw = 500_000_000_000_000_000.0_f64;
        g.update_edge_from_reserves(0, 1, v2_pool_id, 1.0e18, weth_raw, 0.997);

        assert!(
            g.edges_from(0)
                .iter()
                .find(|e| e.pool_id == v2_pool_id)
                .expect("V2 edge")
                .filtered,
            "V2 dust WETH pool must still be filtered after the V3 carve-out"
        );
    }

    #[test]
    fn test_decimal_neutral_18_18_unchanged() {
        // Two 18-decimal tokens: 10^(18-18) = 1, so the corrected rate must
        // exactly equal the pre-change behavior (no regression).
        let mut g = PriceGraph::new(3);
        let pool_id = make_pool_id(1, ProtocolType::UniswapV2);
        g.add_edge(
            0,
            1,
            2.0,
            pool_id,
            Address::repeat_byte(1),
            ProtocolType::UniswapV2,
            U256::from(1_000u64),
        );
        // Vertices default to 18 decimals; do not set anything.
        g.update_edge_from_reserves(0, 1, pool_id, 1000.0, 2000.0, 0.997);

        // Same expectation as the legacy test_update_edge_from_reserves.
        let expected_weight = -(2.0 * 0.997_f64).ln();
        let edge = &g.all_edges()[0];
        assert!(
            (edge.weight - expected_weight).abs() < 1e-12,
            "18/18 decimal pair must match pre-change weight"
        );
    }

    #[test]
    fn clone_retaining_pools_filters_edges() {
        use std::collections::HashSet;
        let mut g = PriceGraph::new(3);
        let hot_id = make_pool_id(10, ProtocolType::UniswapV2);
        let cold_id = make_pool_id(11, ProtocolType::SushiSwap);
        g.add_edge(0, 1, 1.2, hot_id, hot_id.address, ProtocolType::UniswapV2, U256::from(100));
        g.add_edge(1, 0, 0.8, hot_id, hot_id.address, ProtocolType::UniswapV2, U256::from(100));
        g.add_edge(0, 2, 1.5, cold_id, cold_id.address, ProtocolType::SushiSwap, U256::from(50));
        g.add_edge(2, 0, 0.6, cold_id, cold_id.address, ProtocolType::SushiSwap, U256::from(50));

        let mut allowed = HashSet::new();
        allowed.insert(hot_id.address);
        let filtered = g.clone_retaining_pools(&allowed);
        assert_eq!(filtered.num_edges(), 2);
        assert!(filtered.all_edges().iter().all(|e| e.pool_address == hot_id.address));
    }

    #[test]
    fn clone_retaining_empty_set_returns_full_graph() {
        use std::collections::HashSet;
        let mut g = PriceGraph::new(2);
        let pid = make_pool_id(1, ProtocolType::UniswapV2);
        g.add_edge(0, 1, 1.0, pid, pid.address, ProtocolType::UniswapV2, U256::ZERO);
        let filtered = g.clone_retaining_pools(&HashSet::new());
        assert_eq!(filtered.num_edges(), g.num_edges());
    }
}

use crate::price_graph::PriceGraph;
use arc_swap::ArcSwap;
use std::sync::atomic::{AtomicU64, Ordering};
use std::sync::Arc;

/// Immutable snapshot of the price graph state at a particular block.
///
/// Snapshots are produced by the writer (state updater) and consumed by
/// readers (detector threads) through the [`SnapshotManager`]. Because
/// they are wrapped in `Arc`, readers get zero-copy access.
#[derive(Debug, Clone)]
pub struct GraphSnapshot {
    /// The price graph at this point in time.
    pub graph: PriceGraph,
    /// Ethereum block number this snapshot corresponds to.
    pub block_number: u64,
    /// Wall-clock timestamp in nanoseconds when the snapshot was created.
    pub timestamp_ns: i64,
    /// Monotonically increasing snapshot version.
    pub version: u64,
}

impl GraphSnapshot {
    pub fn new(graph: PriceGraph, block_number: u64, timestamp_ns: i64, version: u64) -> Self {
        Self {
            graph,
            block_number,
            timestamp_ns,
            version,
        }
    }
}

/// MVCC snapshot manager using `ArcSwap` for lock-free publish/load.
///
/// Writers atomically swap in new snapshot versions; readers obtain
/// zero-copy immutable references via `Guard<Arc<GraphSnapshot>>`.
/// This is the core concurrency primitive that allows the detection
/// engine to read a consistent graph while the state updater writes
/// the next version.
pub struct SnapshotManager {
    /// The current published snapshot.
    current: Arc<ArcSwap<GraphSnapshot>>,
    /// Monotonically increasing version counter.
    version_counter: AtomicU64,
}

impl SnapshotManager {
    /// Create a new snapshot manager with an initial (empty) graph.
    pub fn new(initial_graph: PriceGraph) -> Self {
        let snapshot = GraphSnapshot::new(initial_graph, 0, 0, 0);
        Self {
            current: Arc::new(ArcSwap::from_pointee(snapshot)),
            version_counter: AtomicU64::new(0),
        }
    }

    /// Get a zero-copy reference to the current snapshot.
    ///
    /// The returned `Guard` keeps the snapshot alive for the duration
    /// of the borrow. This is extremely cheap (no atomic increment on
    /// the fast path in many cases).
    #[inline]
    pub fn load(&self) -> arc_swap::Guard<Arc<GraphSnapshot>> {
        self.current.load()
    }

    /// Get a full `Arc<GraphSnapshot>` clone (increments the refcount).
    ///
    /// Use this when you need to hold onto the snapshot for longer than
    /// a single scope, e.g. passing it to a spawned task.
    #[inline]
    pub fn load_full(&self) -> Arc<GraphSnapshot> {
        self.current.load_full()
    }

    /// Atomically publish a new snapshot, replacing the current one.
    ///
    /// Existing readers holding a `Guard` or `Arc` to the old snapshot
    /// are unaffected -- the old data is kept alive until all references
    /// are dropped.
    pub fn publish(&self, graph: PriceGraph, block_number: u64, timestamp_ns: i64) {
        let version = self.version_counter.fetch_add(1, Ordering::SeqCst) + 1;
        let snapshot = Arc::new(GraphSnapshot::new(graph, block_number, timestamp_ns, version));
        self.current.store(snapshot);
    }

    /// Get the current version number (number of publishes so far).
    #[inline]
    pub fn version(&self) -> u64 {
        self.version_counter.load(Ordering::SeqCst)
    }
}

#[cfg(test)]
mod tests {
    use super::*;

    fn make_graph(n: usize) -> PriceGraph {
        PriceGraph::new(n)
    }

    #[test]
    fn test_snapshot_creation() {
        let snap = GraphSnapshot::new(make_graph(5), 100, 12345, 1);
        assert_eq!(snap.block_number, 100);
        assert_eq!(snap.timestamp_ns, 12345);
        assert_eq!(snap.version, 1);
        assert_eq!(snap.graph.num_vertices(), 5);
    }

    #[test]
    fn test_manager_initial_state() {
        let mgr = SnapshotManager::new(make_graph(10));
        assert_eq!(mgr.version(), 0);

        let snap = mgr.load();
        assert_eq!(snap.block_number, 0);
        assert_eq!(snap.version, 0);
        assert_eq!(snap.graph.num_vertices(), 10);
    }

    #[test]
    fn test_publish_increments_version() {
        let mgr = SnapshotManager::new(make_graph(5));
        assert_eq!(mgr.version(), 0);

        mgr.publish(make_graph(5), 100, 1000);
        assert_eq!(mgr.version(), 1);

        mgr.publish(make_graph(5), 101, 2000);
        assert_eq!(mgr.version(), 2);

        mgr.publish(make_graph(5), 102, 3000);
        assert_eq!(mgr.version(), 3);
    }

    #[test]
    fn test_publish_updates_snapshot() {
        let mgr = SnapshotManager::new(make_graph(5));

        mgr.publish(make_graph(8), 42, 999);
        let snap = mgr.load();
        assert_eq!(snap.block_number, 42);
        assert_eq!(snap.timestamp_ns, 999);
        assert_eq!(snap.version, 1);
        assert_eq!(snap.graph.num_vertices(), 8);
    }

    #[test]
    fn test_load_full_returns_arc() {
        let mgr = SnapshotManager::new(make_graph(5));
        mgr.publish(make_graph(7), 50, 123);

        let arc = mgr.load_full();
        assert_eq!(arc.block_number, 50);
        assert_eq!(arc.graph.num_vertices(), 7);
    }

    #[test]
    fn test_old_snapshot_survives_publish() {
        let mgr = SnapshotManager::new(make_graph(5));
        mgr.publish(make_graph(5), 100, 1000);

        // Hold a reference to the current snapshot.
        let old_snap = mgr.load_full();
        assert_eq!(old_snap.block_number, 100);

        // Publish a new one.
        mgr.publish(make_graph(5), 200, 2000);

        // Old snapshot is still accessible.
        assert_eq!(old_snap.block_number, 100);
        assert_eq!(old_snap.version, 1);

        // New snapshot is different.
        let new_snap = mgr.load();
        assert_eq!(new_snap.block_number, 200);
        assert_eq!(new_snap.version, 2);
    }

    #[test]
    fn test_concurrent_reads() {
        use std::sync::Arc as StdArc;

        let mgr = StdArc::new(SnapshotManager::new(make_graph(5)));
        mgr.publish(make_graph(5), 100, 1000);

        let handles: Vec<_> = (0..8)
            .map(|_| {
                let mgr = StdArc::clone(&mgr);
                std::thread::spawn(move || {
                    let snap = mgr.load();
                    assert_eq!(snap.block_number, 100);
                    assert_eq!(snap.graph.num_vertices(), 5);
                })
            })
            .collect();

        for h in handles {
            h.join().unwrap();
        }
    }

    #[test]
    fn test_concurrent_read_write() {
        use std::sync::Arc as StdArc;

        let mgr = StdArc::new(SnapshotManager::new(make_graph(5)));

        // Spawn a writer.
        let writer_mgr = StdArc::clone(&mgr);
        let writer = std::thread::spawn(move || {
            for i in 1..=100 {
                writer_mgr.publish(make_graph(5), i, i as i64 * 1000);
            }
        });

        // Spawn readers that continuously load.
        let readers: Vec<_> = (0..4)
            .map(|_| {
                let mgr = StdArc::clone(&mgr);
                std::thread::spawn(move || {
                    for _ in 0..200 {
                        let snap = mgr.load();
                        // Snapshot should always be internally consistent.
                        assert_eq!(snap.graph.num_vertices(), 5);
                        // Block number should be non-negative.
                        assert!(snap.block_number <= 100);
                    }
                })
            })
            .collect();

        writer.join().unwrap();
        for r in readers {
            r.join().unwrap();
        }

        // Final state should reflect the last publish.
        let final_snap = mgr.load();
        assert_eq!(final_snap.block_number, 100);
        assert_eq!(mgr.version(), 100);
    }
}

use alloy::primitives::Address;
use std::collections::HashMap;

/// Bidirectional mapping between token addresses and graph vertex indices.
///
/// Every unique token that appears in the monitored pool set is assigned a
/// stable integer index. This index is used as the vertex identifier in the
/// [`PriceGraph`](crate::price_graph::PriceGraph), avoiding the overhead of
/// hashing `Address` values on every edge lookup.
#[derive(Debug, Clone)]
pub struct TokenIndex {
    /// Forward map: address -> index.
    addr_to_idx: HashMap<Address, usize>,
    /// Reverse map: index -> address (position = index).
    idx_to_addr: Vec<Address>,
}

impl TokenIndex {
    /// Create an empty token index.
    pub fn new() -> Self {
        Self {
            addr_to_idx: HashMap::new(),
            idx_to_addr: Vec::new(),
        }
    }

    /// Get the index for a token address, inserting it if it does not yet
    /// exist. The returned index is stable for the lifetime of this
    /// `TokenIndex`.
    pub fn get_or_insert(&mut self, address: Address) -> usize {
        if let Some(&idx) = self.addr_to_idx.get(&address) {
            idx
        } else {
            let idx = self.idx_to_addr.len();
            self.addr_to_idx.insert(address, idx);
            self.idx_to_addr.push(address);
            idx
        }
    }

    /// Look up the index for a token address. Returns `None` if the token
    /// has not been indexed.
    #[inline]
    pub fn get_index(&self, address: &Address) -> Option<usize> {
        self.addr_to_idx.get(address).copied()
    }

    /// Look up the address for a given index. Returns `None` if the index
    /// is out of bounds.
    #[inline]
    pub fn get_address(&self, index: usize) -> Option<&Address> {
        self.idx_to_addr.get(index)
    }

    /// Total number of tokens indexed.
    #[inline]
    pub fn len(&self) -> usize {
        self.idx_to_addr.len()
    }

    /// Returns `true` if no tokens have been indexed.
    #[inline]
    pub fn is_empty(&self) -> bool {
        self.idx_to_addr.is_empty()
    }

    /// Get a slice of all indexed addresses in index order.
    #[inline]
    pub fn all_addresses(&self) -> &[Address] {
        &self.idx_to_addr
    }

    /// Check whether a token address has been indexed.
    #[inline]
    pub fn contains(&self, address: &Address) -> bool {
        self.addr_to_idx.contains_key(address)
    }
}

impl Default for TokenIndex {
    fn default() -> Self {
        Self::new()
    }
}

#[cfg(test)]
mod tests {
    use super::*;
    use alloy::primitives::Address;

    #[test]
    fn test_new_index_is_empty() {
        let idx = TokenIndex::new();
        assert!(idx.is_empty());
        assert_eq!(idx.len(), 0);
        assert!(idx.all_addresses().is_empty());
    }

    #[test]
    fn test_default_is_empty() {
        let idx = TokenIndex::default();
        assert!(idx.is_empty());
    }

    #[test]
    fn test_insert_single() {
        let mut idx = TokenIndex::new();
        let addr = Address::repeat_byte(0x01);
        let i = idx.get_or_insert(addr);
        assert_eq!(i, 0);
        assert_eq!(idx.len(), 1);
        assert!(!idx.is_empty());
    }

    #[test]
    fn test_insert_multiple() {
        let mut idx = TokenIndex::new();
        let a = Address::repeat_byte(0x01);
        let b = Address::repeat_byte(0x02);
        let c = Address::repeat_byte(0x03);

        assert_eq!(idx.get_or_insert(a), 0);
        assert_eq!(idx.get_or_insert(b), 1);
        assert_eq!(idx.get_or_insert(c), 2);
        assert_eq!(idx.len(), 3);
    }

    #[test]
    fn test_insert_duplicate_returns_same_index() {
        let mut idx = TokenIndex::new();
        let addr = Address::repeat_byte(0xAA);

        let first = idx.get_or_insert(addr);
        let second = idx.get_or_insert(addr);
        assert_eq!(first, second);
        assert_eq!(idx.len(), 1, "duplicate insert should not increase size");
    }

    #[test]
    fn test_get_index_existing() {
        let mut idx = TokenIndex::new();
        let addr = Address::repeat_byte(0x05);
        let i = idx.get_or_insert(addr);
        assert_eq!(idx.get_index(&addr), Some(i));
    }

    #[test]
    fn test_get_index_nonexistent() {
        let idx = TokenIndex::new();
        let addr = Address::repeat_byte(0x05);
        assert_eq!(idx.get_index(&addr), None);
    }

    #[test]
    fn test_get_address_existing() {
        let mut idx = TokenIndex::new();
        let addr = Address::repeat_byte(0x07);
        let i = idx.get_or_insert(addr);
        assert_eq!(idx.get_address(i), Some(&addr));
    }

    #[test]
    fn test_get_address_out_of_bounds() {
        let idx = TokenIndex::new();
        assert_eq!(idx.get_address(0), None);
        assert_eq!(idx.get_address(999), None);
    }

    #[test]
    fn test_bidirectional_consistency() {
        let mut idx = TokenIndex::new();
        let addresses: Vec<Address> = (1..=10).map(Address::repeat_byte).collect();

        for &addr in &addresses {
            idx.get_or_insert(addr);
        }

        // Forward then reverse.
        for &addr in &addresses {
            let i = idx.get_index(&addr).unwrap();
            assert_eq!(idx.get_address(i), Some(&addr));
        }

        // Reverse then forward.
        for i in 0..idx.len() {
            let addr = idx.get_address(i).unwrap();
            assert_eq!(idx.get_index(addr), Some(i));
        }
    }

    #[test]
    fn test_contains() {
        let mut idx = TokenIndex::new();
        let addr = Address::repeat_byte(0x10);

        assert!(!idx.contains(&addr));
        idx.get_or_insert(addr);
        assert!(idx.contains(&addr));
    }

    #[test]
    fn test_all_addresses() {
        let mut idx = TokenIndex::new();
        let a = Address::repeat_byte(0x01);
        let b = Address::repeat_byte(0x02);
        let c = Address::repeat_byte(0x03);

        idx.get_or_insert(a);
        idx.get_or_insert(b);
        idx.get_or_insert(c);

        let all = idx.all_addresses();
        assert_eq!(all.len(), 3);
        assert_eq!(all[0], a);
        assert_eq!(all[1], b);
        assert_eq!(all[2], c);
    }

    #[test]
    fn test_clone() {
        let mut idx = TokenIndex::new();
        let addr = Address::repeat_byte(0x42);
        idx.get_or_insert(addr);

        let cloned = idx.clone();
        assert_eq!(cloned.len(), 1);
        assert_eq!(cloned.get_index(&addr), Some(0));
        assert_eq!(cloned.get_address(0), Some(&addr));
    }

    #[test]
    fn test_well_known_tokens() {
        use aether_common::types::addresses;
        let mut idx = TokenIndex::new();

        let weth_idx = idx.get_or_insert(addresses::WETH);
        let usdc_idx = idx.get_or_insert(addresses::USDC);
        let dai_idx = idx.get_or_insert(addresses::DAI);

        assert_ne!(weth_idx, usdc_idx);
        assert_ne!(usdc_idx, dai_idx);
        assert_eq!(idx.get_index(&addresses::WETH), Some(weth_idx));
        assert_eq!(idx.get_address(dai_idx), Some(&addresses::DAI));
    }
}

